-- Clear existing business data
DELETE FROM chain_businesses;
DELETE FROM business_categories;
DELETE FROM businesses;

CREATE TABLE businesses (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        address TEXT NOT NULL,
        latitude REAL NOT NULL,
        longitude REAL NOT NULL,
        phone TEXT,
        website TEXT,
        category TEXT NOT NULL,
        lfa_member INTEGER DEFAULT 0,
        member_since TEXT,
        verified INTEGER DEFAULT 0,
        status TEXT DEFAULT 'active',
        created_at TEXT DEFAULT CURRENT_TIMESTAMP,
        updated_at TEXT DEFAULT CURRENT_TIMESTAMP
      , primary_category TEXT, subcategory TEXT, business_description TEXT, products_services TEXT, keywords TEXT, enrichment_status TEXT DEFAULT 'pending', enrichment_date TEXT, enrichment_source TEXT, business_attributes TEXT, hours_of_operation TEXT, social_media_links TEXT, special_features TEXT);



CREATE TABLE business_categories (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL UNIQUE,
  parent_category_id TEXT REFERENCES business_categories(id),
  display_name TEXT NOT NULL,
  description TEXT,
  keywords TEXT, -- JSON array of keywords for this category
  icon_name TEXT, -- Icon identifier for UI
  color_code TEXT, -- Hex color for UI theming
  sort_order INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

