INSERT INTO businesses VALUES('ce81ad2f-f6e9-49b2-83fb-46699ed88bce','[POPPED] Artisan Popcorn','510 N. 7th Avenue Suite 140, Tucson, AZ 85705',32.24522927228665737,-111.0174378617306558,'(520) 940-0115','www.poppedartisan.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','retail_shopping','gifts_novelty','[POPPED] Artisan Popcorn is a unique business specializing in the creation and sale of artisan popcorn. They serve a wide range of customers, from individuals looking for a tasty snack to businesses seeking unique corporate gifts. Their popcorn is gluten-free, vegan, and nut-free, making it suitable for a wide variety of dietary needs. They distinguish themselves by offering a variety of collections, each named after a famous Arizona landmark. They also offer a ''Popcorn of the Month'' club for those who want to regularly enjoy their products.','["The Saguaro Collection","The Sedona Collection","The Grand Canyon Collection","Popcorn of the Month Club","E-Gift Card"]','artisan popcorn, gluten-free, vegan, nut-free, gift collections, popcorn of the month club','completed','2025-08-24T09:55:39.816Z','firecrawl','{"locally_owned":true,"specialty_focus":"artisan popcorn"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('0ba33fd2-b5eb-411b-b0c0-d6a70b3be275','10 to 1 Public Relations','7975 N Hayden Road, Suite C-300, Scottsdale, AZ 85258',33.44908384552190483,-111.9742805550517347,'480-789-0743','www.10to1pr.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','professional_services','marketing_advertising','10 to 1 Public Relations is a professional marketing and advertising business based in Scottsdale, Arizona. They offer a comprehensive range of public relations services that are targeted, compelling, and designed to achieve their clients'' goals. With a focus on strategic communications, they have helped organizations across various industries, including finance, health and wellness, real estate, manufacturing, construction, technology, and transportation, to achieve their goals. They distinguish themselves by offering unique services such as Deepfake Crisis Management and a ''No Jerks Policy''. They also take pride in their awards and accolades, reflecting their hard work and dedication to serving their clients.','["Awards Submissions","Crisis Communications Management","Employee Communication","Media Training","Public Affairs","Social Media Management","Speaking Opportunities","Strategic Communications"]','Public Relations, Strategic Communications, Media Relations, Crisis Management, Corporate Social Responsibility, Deepfake Crisis Management, Trade Show Media, White Label PR Services','completed','2025-08-24T09:55:48.498Z','firecrawl','{"locally_owned":true,"specialty_focus":"Strategic Communications and Crisis Management"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('def125e4-4e1e-42e0-a7b5-c52689ecd7a4','12 West Brewing','12 W Main, Mesa, AZ 85201',33.43561276378612491,-111.8193775335904547,'480-508-7018','12westbrewing.com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','food_dining','brewery_winery','12 West Brewing is a brewery and taproom business with multiple locations in Arizona, serving people with a taste for craft beers and a comfortable dining experience. It distinguishes itself by offering a variety of locally brewed beers, including Pilsners, Belgian Wheat, Coffee Stout, and several types of IPA. Each location also serves as a taproom, providing a relaxed environment for customers to enjoy their products. Their commitment to quality and local sourcing sets them apart in the brewery industry.','["ZONA Pilsner","Blap!Blap! Belgian Wheat","Midnight Run Coffee Stout","Super Beaker IPA","FRONTSIDE IPA","Cirrus Haze New England Style IPA"]','brewery, taproom, craft beer, local brew, Arizona, dining','completed','2025-08-24T09:55:56.096Z','firecrawl','{"locally_owned":true,"specialty_focus":"Crafting unique and locally sourced beers"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('d84c4714-80e7-4466-a2e2-ede89afa45df','1601 Design','1425 E Portland St, Phoenix, AZ 85006',33.46041499999999758,-112.0514177000000017,'4805291310','1601design.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','professional_services','marketing_advertising','1601 Design is a design and branding specialist business serving businesses with their design and branding needs. It distinguishes itself by providing strategic solutions and plans in line with client goals, developing strategy, executing design, and offering value-added partnership. The business also has experience in video editing and motion graphics, digital design, logo design, and large format printing. The business prides itself on its award-winning design and its ability to add value faster than it adds costs.','["Brand Strategy","Professional Creative","Video Editing and Motion Graphics","Digital Design","Logo Design","Large Format Printing"]','design, branding, strategy, video editing, motion graphics, digital design, logo design, large format printing','completed','2025-08-24T09:56:04.041Z','firecrawl','{"locally_owned":true,"specialty_focus":"Design and Branding"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('8490d5db-1386-4b16-b9ff-3e47ecb44b45','180 Degrees Design + Build','4955 N 7th Ave, Phoenix, AZ 85013',33.50865859999999685,-112.0822629000000034,'6022880138','180degreesinc.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','professional_services','consulting','180 Degrees Design + Build is an award-winning, architect-led design-build firm based in Phoenix, Arizona. They are dedicated to providing the highest level of quality design and construction for discerning clients who value innovation, sustainability, and craft. Their team includes licensed architects, architecturally trained specialists, and fabricators. They specialize in commercial, public, and high-end residential architecture, creating memorable spaces for their clients. They are also active participants of Local First Arizona, supporting local businesses and events.','["Commercial Architecture","Residential Architecture","Civic & Cultural Architecture","Architectural Fabrication","Pre-Construction Design","Construction"]','design-build, architecture, commercial, residential, sustainability, innovation, craft, Phoenix, Arizona','completed','2025-08-24T09:56:12.149Z','firecrawl','{"locally_owned":true,"specialty_focus":"Design-build architecture with a focus on innovation, sustainability, and craft"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('dd44f1a9-6ba7-4026-adbe-3ffaf09abf8a','1899 Bar and Grill','307 W Dupont Ave, Flagstaff, AZ 86001',35.19364639999999867,-111.6550849999999997,'(928) 523-1899','https://www.1899barandgrill.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','food_dining','restaurant','1899 Bar and Grill is a restaurant located in Flagstaff, Arizona. It offers a relaxed atmosphere and uniquely inviting ambiance, serving a variety of food and drink options. The culinary crew of 1899 uses global accents to create an array of approachable flavors that pair nicely with their complete wine list, specialty cocktails, and local beers on tap. The restaurant distinguishes itself by its historic location on NAU''s north campus and its free parking service, with parking vouchers provided upon request.','["food","drinks","wine","specialty cocktails","local beers"]','restaurant, bar and grill, Flagstaff, Arizona, NAU, global accents, wine list, specialty cocktails, local beers, free parking','completed','2025-08-24T23:48:19.194Z','firecrawl','{"locally_owned":true,"specialty_focus":"global accents in food and drink offerings"}',NULL,NULL,NULL);
