INSERT INTO businesses VALUES('2007d251-57cc-4fad-8a74-a7b0b87fb0e1','1989 BAKE HOUSE','3355 South Camino Del Sol, Green Valley, AZ 85622',31.82092129999999842,-111.0154050000000012,'(520) 540-5775','1989Bakehouse.Com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','food_dining','bakery','1989 Bake House is a bakery located in Green Valley, Arizona. They specialize in creating exquisite flavors and delightful creations, with a focus on flavor, quality, and consistency. They offer a range of baked goods including cookies, brownies, and other savory items. They also serve coffee. Their products are made with high-quality ingredients such as imported Callebaut chocolate, local flour, and local eggs. They are known for their unique cookie flavors such as Chai Oreo, Triple Chocolate Dipped, Dubai Pistachio, and Matcha Strawberry. The bakery is open daily and also offers online ordering and wholesale options.','["Cookies","Brownies","Savory items","Coffee","Online ordering","Wholesale"]','bakery, cookies, brownies, Callebaut chocolate, local ingredients, unique flavors, Green Valley, Arizona, 1989 Bake House','completed','2025-08-24T23:48:30.219Z','firecrawl','{"locally_owned":true,"specialty_focus":"Unique cookie flavors and high-quality ingredients"}',NULL,NULL,NULL);
