INSERT INTO businesses VALUES('31d0ad97-3714-4365-8733-273f66cf9a6f','Abby Lee Farms','1355 West Iron Springs Road, Prescott, AZ 86305',33.46925802628366143,-112.0356516745876263,'(480) 381-1074','https://abbyleeaz.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','retail_shopping','grocery_market','Abby Lee Farms is a premier grower in Arizona that specializes in the production and sale of high-quality compost, houseplants, edible foliage, and produce. They are dedicated to bringing the best tasting produce and quality plants to the market at competitive prices. They also offer composting services for gardening enthusiasts. Their unique selling proposition is their commitment to freshness, local sourcing, and delicious taste in their produce. They serve individuals, families, and businesses in need of fresh, locally grown produce and plants.','["Compost","Houseplants","Edible Foliage","Fresh Produce"]','Abby Lee Farms, Arizona grower, quality compost, houseplants, edible foliage, fresh produce, local sourcing, competitive prices','completed','2025-08-25T00:50:12.402Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Compost and locally grown produce"}',NULL,NULL,NULL);
