INSERT INTO businesses VALUES('1ee1a6b2-1b62-4337-a3c1-8fb8d33e73b5','Ahwatukee Farmers Market','4700 East Warner Road, Tempe, AZ 85284',33.33463689999999958,-111.9115996999999965,'(623) 848-1234','https://arizonacommunityfarmersmarkets.com/ahwatukee-farmers-market','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','retail_shopping','grocery_market','Ahwatukee Farmers Market is a local grocery market in Arizona that offers a variety of fresh, local, and seasonal produce, herbs, flowers, value-added foods, fresh baked goods, natural meats, and seafood. The market also features a selection of local arts and crafts. It serves the local community, providing them with a place to purchase fresh, locally sourced food and products. The market is unique in that it is enrolled in the AZFMNP/WIC program, making it accessible to a wider range of customers. It operates on a seasonal schedule, with different operating hours for the winter and summer months.','["Seasonal Produce","Herbs","Flowers","Value Added Foods","Fresh Baked Goods","Natural Meats","Seafood","Local Arts and Crafts"]','Farmers Market, Local Produce, Seasonal Produce, Fresh Baked Goods, Natural Meats, Seafood, Local Arts and Crafts, AZFMNP/WIC Program','completed','2025-08-25T00:06:48.280Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Local and Seasonal Produce"}',NULL,NULL,NULL);
