INSERT INTO businesses VALUES('1f4aa5da-4534-46a6-ae77-07973ceb12c6','Angry Acres Ranch','570 E Tumbleweed Lane, Benson, AZ 85602',33.45436294582505355,-112.0545453371881876,'520-442-0425','https://angryacresranch.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','arts_entertainment','recreation','Angry Acres Ranch is a recreational business located in Benson, Arizona. It offers a unique experience to animal lovers and those interested in ranch life. The ranch is home to a variety of animals and offers educational tours, events such as annual spring shearing, and an online shop. The business serves individuals who are interested in learning about ranch life, participating in ranch events, or purchasing animal-related products. It distinguishes itself by providing a hands-on experience with animals and offering unique products related to the animals they raise.','["Ranch Tours","Animal Education","Annual Spring Shearing Event","Online Shop for Animal-Related Products"]','Ranch, Recreation, Animal Education, Tours, Events, Online Shop','completed','2025-08-25T00:07:47.866Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Ranch Life and Animal Education"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('041bf4e4-273a-4aa2-8bfe-331487d2a2cf','Aniles and Company, PLLC','3033 N Central ave Suite 615, Phoenix, AZ 85012',33.44164797765454011,-112.0461786010889683,'4803004993','anilescpa.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','professional_services','accounting_tax','Aniles and Company, PLLC is a certified public accounting and advisory firm based in Phoenix, Arizona. They offer a wide range of services including accounting, taxation, advisory, auditing and attestation. The firm serves both for-profit and non-profit entities, helping them maximize their potential. They distinguish themselves by providing exceptional audits and delivering value to stakeholders while also bringing independent insights to management and governance. They also offer tax advisory services, helping organizations navigate the complex tax world, leverage tax credits, and develop effective tax strategies.','["Accounting","Taxation","Advisory","Auditing and Attestation"]','Accounting, Taxation, Advisory, Auditing, Attestation, For-profit, Non-profit','completed','2025-08-24T10:10:50.404Z','firecrawl','{"locally_owned":true,"specialty_focus":"Accounting and Tax services for both for-profit and non-profit entities"}',NULL,NULL,NULL);
