INSERT INTO businesses VALUES('0225939d-ed42-418b-90ca-e95d968e1bb4','AT Oasis Coffee And Tea Shop','4613 E Thomas Rd, Phoenix, AZ 85018',33.47962739999999827,-111.9819508000000071,'(602) 957-2054','https://atoasiscoffee.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','food_dining','cafe','AT Oasis Coffee And Tea Shop is a specialty cafe located in Phoenix, Arizona. The shop is known for its exclusive import of Ethiopian specialty coffee from the Sidamo and Yirgacheffe regions. The owner, Aisha Tedros, personally tests each crop to ensure the quality and authenticity of the coffee. In addition to coffee, the shop also offers tea, baked goods, and savory treats. They also provide an online store for customers to shop for their coffee selection from home and offer a membership program for regular customers. The shop is highly rated for its quality products, friendly staff, and unique Ethiopian coffee experience.','["Ethiopian specialty coffee","Tea","Baked goods","Savory treats","Online store","Membership program"]','Ethiopian specialty coffee, Sidamo, Yirgacheffe, Aisha Tedros, online store, membership program, Phoenix, Arizona','completed','2025-08-24T10:06:28.196Z','firecrawl','{"locally_owned":true,"specialty_focus":"Ethiopian specialty coffee"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('07b743df-8192-44b8-8e39-c1a472f0cb53','Ate Kei''s Filipino Treats','3856 E Monte Vista Dr, Tucson, AZ 85716',32.25958419999999905,-110.9107532999999962,'(520) 309-1358','Atekeistreats.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','food_dining','bakery','Ate Kei''s Filipino Treats is a bakery specializing in Filipino delicacies and treats, serving the Arizona community. This business distinguishes itself by offering a unique selection of Filipino treats, including Buko Pandan Crinkle, Chili Mango Cookie, Ube Oreo Brownie, and Ube S''mores Brownie. As a locally-owned business, Ate Kei''s Filipino Treats takes pride in bringing a taste of the Philippines to Arizona, offering online ordering and local pick-up options for their customers.','["Buko Pandan Crinkle","Chili Mango Cookie","Pandan Crinkle Turtle Sticker","Ube Crinkle Turtle Sticker","Ube Oreo Brownie","Ube S''mores Brownie"]','Filipino treats, bakery, Arizona, local pick-up, online ordering, Buko Pandan Crinkle, Chili Mango Cookie, Ube Oreo Brownie, Ube S''mores Brownie','completed','2025-08-24T10:19:57.957Z','firecrawl','{"locally_owned":true,"specialty_focus":"Filipino treats"}',NULL,NULL,NULL);
