INSERT INTO businesses VALUES('13c00d97-d57e-4ff5-8883-0dfed5940690','Auto Glass Medix','2914 E Cactus Rd, Phoenix, AZ 85032',33.59730100000000163,-112.0192354999999935,'(480) 408-3453','www.autoglassmedix.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','automotive','auto_repair','Auto Glass Medix is a family-owned automotive repair business that specializes in auto glass repair and replacement services. Serving the entire Valley in Arizona, they offer mobile services for the convenience of their customers, ensuring safety and quality in their work. They pride themselves on their customer service, offering a lifetime workmanship warranty on their repairs. Auto Glass Medix also works with over 80 insurance companies, assisting customers in filing claims and accepting all pricing, thereby reducing out-of-pocket costs for their clients.','["Auto glass replacement","Windshield repair","Mobile repair service","Insurance claim assistance"]','auto glass repair, windshield replacement, mobile service, lifetime warranty, insurance claim assistance','completed','2025-08-24T10:44:32.515Z','firecrawl','{"locally_owned":true,"specialty_focus":"auto glass repair and replacement"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('2a956537-04f2-4565-ad04-bc191786e4ae','AV Concepts','1917 West 1st Street, Tempe, AZ 85281',33.42899369999999948,-111.9683959000000044,'480-557-6013','www.avconcepts.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','professional_services','consulting','AV Concepts is a professional consulting business that specializes in providing comprehensive AV solutions for event professionals. They serve a diverse clientele including event planners, associations, agencies, and venues. AV Concepts stands out by leveraging cutting-edge technology to create unforgettable experiences for their clients. They are committed to meticulous pre-production, reliable equipment, and experienced operators to ensure the success of each event. They also offer tailored solutions to meet the unique needs of each client, rejecting a one-size-fits-all mentality.','["General Sessions","Breakout Solutions","Stage & Scenic Project Management","Unique Activations","Drafting & Rigging","Virtual & Streaming","Holographic Experiences","Venue Solutions"]','AV solutions, event professionals, technology, creativity, pre-production, equipment, operators, tailored solutions','completed','2025-08-25T00:34:12.291Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"AV solutions for events"}',NULL,NULL,NULL);
