INSERT INTO businesses VALUES('15179112-2f91-4244-b26f-4fd1131f5155','Awareness Ranch','12626 W Blue Aloe St, Tucson, AZ 85735',32.2287580837341281,-110.9422841386114839,'(707) 339-6212','https://www.awarenessranch.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','education_training','workshops_seminars','Awareness Ranch is a unique business focused on sustainable agriculture and natural building practices. Located in Tucson, Arizona, they offer a variety of workshops and seminars to educate the community on permaculture practices and natural building methods. In addition to their educational programs, they also cultivate and sell a seasonal variety of locally grown produce. Their produce is sold at farmers'' markets, independent natural food stores, and select local restaurants and bars across Southern Arizona. They also operate as a general and electrical contractor, specializing in projects that utilize alternative natural building methods.','["Natural building workshops","Permaculture practices seminars","Seasonal variety of crops","General and electrical contracting services"]','sustainable agriculture, natural building, workshops, community education, local produce, general contractor, electrical contractor','completed','2025-08-24T10:47:03.348Z','firecrawl','{"locally_owned":true,"specialty_focus":"Sustainable agriculture and natural building"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('210975e0-b51f-4e81-b176-33756894d228','Awesome Oat Cookies','2320 E Baseline Rd, Phoenix, AZ 85042',33.37950219999999746,-112.0308923000000049,'(855) 200-0906','https://www.awesomeoatcookies.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:30','2025-08-11 18:48:30','food_dining','bakery','Awesome Oat Cookies is a bakery business based in Phoenix, Arizona, specializing in the production and delivery of gourmet oat cookies. They serve customers nationwide, offering a variety of cookie flavors and types, including vegan and protein cookies. What sets them apart is their focus on using real ingredients and handcrafting their cookies, rather than using ready-to-use dough or bulk mixes. They offer a wide range of cookie gift baskets, making them a popular choice for gifts for various occasions such as birthdays, business events, and everyday treats.','["Gourmet Oat Cookies","Vegan Cookies","Protein Cookies","Cookie Gift Baskets","Nationwide Cookie Delivery"]','gourmet oat cookies, cookie delivery, vegan cookies, protein cookies, cookie gift baskets, handcrafted cookies, real ingredients','completed','2025-08-25T00:13:17.607Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"handcrafted gourmet oat cookies"}',NULL,NULL,NULL);
