INSERT INTO businesses VALUES('11a47581-6ca0-43dd-9220-bff62c088a04','Bar X Bar Cattle','5075 South Hwy 186, Willcox, AZ 85643',33.41200578608119542,-112.1186965943733754,'5203907101','Barxbarcattle.com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Bar X Bar Cattle is a family-owned and operated cattle ranch that specializes in the breeding and sale of Full Blood Wagyu, Registered Angus, and Commercial Angus cross beef. The business prides itself on its unique cow-calf operation, allowing its cattle to free-range graze from irrigated pasture to natural pasture. The calves are allowed to stay with their mothers until they reach over 500 lbs, and after weaning, they are moved onto a five-section pasture that includes 300-acres of irrigated pastures. They are able to graze free until they reach their marketing weight.','["Full Blood Wagyu beef","Registered Angus beef","Commercial Angus cross beef"]','Wagyu beef, Angus beef, family-owned, free-range, irrigated pasture, natural pasture, cow-calf operation','completed','2025-08-24T10:40:19.761Z','firecrawl','{"locally_owned":true,"specialty_focus":"Breeding and sale of premium beef cattle"}',NULL,NULL,NULL);
