INSERT INTO businesses VALUES('001061f4-d349-4fbb-b517-79f66519f43c','Barb''s Bakery','2929 N. 24th Street, Phoenix, AZ 85016',33.48087989999999792,-112.0300790999999947,'(602) 957-4422','www.barbsbakery.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','bakery','Barb''s Bakery is a locally owned bakery in Phoenix, Arizona that has been serving the community for over 40 years. They offer a wide variety of sweet treats, including cookies, desserts, wedding cakes, breads, pastries, and cupcakes. All their pastries are made from scratch and they also offer custom decorated cookies and cakes. They have a strong reputation in the community, with customers praising the quality of their products and the friendliness of their staff. They also offer online ordering for pickup.','["Cookies","Desserts","Wedding Cakes","Breads & Pastries","Cupcakes","Layered Cakes"]','bakery, Phoenix, wedding cakes, custom cookies, pastries, Noble breads','completed','2025-08-24T10:01:57.937Z','firecrawl','{"locally_owned":true,"specialty_focus":"Custom decorated cookies and cakes"}',NULL,NULL,NULL);
