INSERT INTO businesses VALUES('2fa09795-5bff-4d6b-8979-4990da1f149b','Berthas Restaurant','1212 S 28 AVE, Phoenix, AZ 85009',33.62643750000000153,-112.1201518999999963,'602-283-4422','https://berthaselsabordelosmochis.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','restaurant','Bertha''s Restaurant is a Mexican restaurant located in Phoenix, Arizona. It offers a wide range of authentic Mexican dishes, including tacos, enchiladas, and quesadillas, as well as a variety of seafood options. The restaurant prides itself on its authentic flavors and fresh ingredients, serving breakfast, lunch, and dinner to residents and visitors of Phoenix and the surrounding cities. Bertha''s Restaurant also offers a kid''s menu, catering to the needs of even the pickiest eaters. Customers can choose to dine in, take out, or have their meals catered.','["Breakfast","Lunch","Dinner","Catering","Kid''s Menu"]','Mexican food, Phoenix, authentic, seafood, catering, dine-in, take-out','completed','2025-08-25T00:44:23.533Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Authentic Mexican cuisine"}',NULL,NULL,NULL);
