INSERT INTO businesses VALUES('1278298e-9aff-4491-9124-ab6fed60ec6d','Boyd''s Farm','Tonto Basin, Tonto Basin, AZ 85553',33.87156149999999855,-111.3141650999999968,'(928) 978-6081','https://www.boydsfarmstand.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Boyd''s Farm is a family-owned farm and grocery market located in Tonto Basin, Arizona. They specialize in producing and selling homemade and farm-fresh products. Their offerings include a variety of jellies, jams, butters, honey, and elderberry tonic. They also sell fruit trees. The farm prides itself on its green thumb, with the ability to make anything grow and thrive. They gather or grow over half the fruits used in all their jellies and jams. They are known for their unique flavors and flavor combinations, and their dedication to providing healthy, tasty products.','["Jelly","Jam","Butters","Honey","Elderberry Tonic","Fruit Trees"]','Boyd''s Farm, homemade products, farm fresh, jellies, jams, butters, honey, elderberry tonic, fruit trees, Arizona farm','completed','2025-08-24T10:42:00.257Z','firecrawl','{"locally_owned":true,"specialty_focus":"Homemade and farm fresh products"}',NULL,NULL,NULL);
