INSERT INTO businesses VALUES('1c9ae1b8-fa15-4bf1-9fed-064f8fd27717','Bread And Honey','4700 E Van Buren st, Phoenix, AZ 85008',33.4513358000000025,-111.9811042000000043,'602-384-7728','https://thebreadandhoneyhouse.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','restaurant','Bread And Honey is a family-owned restaurant located in Phoenix, Arizona, offering a variety of breakfast, lunch, and brunch options. The restaurant is known for its Mexican/American infused menu and its commitment to delivering fresh food with quality ingredients. They also offer catering services for various events such as birthday parties, holiday parties, corporate events, and wedding festivities. The restaurant prides itself on its excellent customer service and its ability to create a cozy, welcoming atmosphere for its customers.','["Breakfast","Lunch","Brunch","Catering services"]','restaurant, catering, breakfast, lunch, brunch, Mexican/American food, fresh food, quality ingredients, family-owned, Phoenix, Arizona','completed','2025-08-24T11:01:24.866Z','firecrawl','{"locally_owned":true,"specialty_focus":"Mexican/American infused menu"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('214ba21f-b83d-4d52-887c-b16bea8866e6','Bread Brothers Bakery','106 E. McKellips Rd. Ste. #111, Mesa, AZ 85201',33.36580688398833417,-111.861147148735327,'(480) 980-0967','breadbrothersbakery.com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','bakery','Bread Brothers Bakery is a bakery business located in Mesa, Arizona, specializing in a variety of breads and baked goods. They serve people with a love for fresh, homemade breads and pastries. The bakery distinguishes itself by offering a wide range of products made from 100% whole grain flour from non-GMO, pesticide-free wheat, emphasizing their commitment to clean food. Their offerings include sandwich bread, sourdough bread, focaccia, bagels, cinnamon rolls, cookies, brownies, croissants, granola, muffins, pizza crust, and buns. They also sell baking mixes, cereals, and kitchen equipment.','["Sandwich Bread","Sourdough Bread","Focaccia","Bagels","Cinnamon Rolls","Cookies","Brownies","Croissants","Granola","Muffins","Pizza Crust","Buns","Baking Mixes","Cereal","Kitchen Equipment"]','bakery, bread, whole grain, non-GMO, clean food, Arizona, Bread Brothers Bakery','completed','2025-08-25T00:13:44.348Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Whole grain, non-GMO, clean food baking"}',NULL,NULL,NULL);
