INSERT INTO businesses VALUES('2c74c74f-a7bd-4088-b844-6a6a0748e6f8','Bridle Path Beeyard','5533 N Central Ave., Phoenix, AZ 85012',33.51811759999999651,-112.0736317000000071,'(602) 622-9300','https://bridlepathbeeyard.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Bridle Path Beeyard is a local beekeeping business based in Phoenix, Arizona. Established in 2016, it focuses on urban beekeeping, promoting pollination, and infusing the genetics of gentle honeybees into the feral honeybee populations. The business offers pure, natural Arizona honey collected from the gardens, trees, and landscapes of Central Phoenix. The honeybees are treated with utmost care and meticulous attention to detail, allowing the colonies to thrive in their natural environment. The business also supports the local beekeeping community by reinvesting a large portion of its revenues back into the colonies for scientific monitoring equipment, enrollment in disease surveillance programs, and other efforts to keep the bees healthy and happy.','["Local Honey","Beekeeping","Pollination Services"]','local honey, beekeeping, natural Arizona honey, urban beekeeping, pollination, honeybees, sustainable beekeeping','completed','2025-08-25T00:38:19.609Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Urban Beekeeping and Local Honey Production"}',NULL,NULL,NULL);
