INSERT INTO businesses VALUES('2d5bd951-fcfd-4d9e-bb7b-95ffee1ed568','Broken Horn D Ranch','11325 Strickland Wash Road, Prescott, AZ 86305',33.45386790496455375,-112.0869569422383734,'(928) 708-9385','www.bhdranch.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','grocery_market','Broken Horn D Ranch is a ranch-based business located in Prescott, Arizona, specializing in the production and sale of grass-fed Criollo beef. This type of beef is known for its tenderness, low fat and cholesterol content, and high protein and Omega 3 levels. The ranch prides itself on sustainable farming practices, raising cattle that are well-adapted to hot, arid climates and consume considerably less feed than traditional English breeds. They offer whole and half beef cuts, providing a healthy and environmentally conscious choice for consumers interested in high-quality, grass-fed beef.','["Grass-fed Criollo beef","Whole beef cuts","Half beef cuts"]','Criollo beef, grass-fed beef, sustainable farming, Arizona ranch, low fat beef, high protein beef, Omega 3 beef','completed','2025-08-25T00:40:56.464Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Grass-fed Criollo beef production"}',NULL,NULL,NULL);
