INSERT INTO businesses VALUES('2a844cbd-e3cd-4e5d-b26d-ce5081707e56','Cahokia PHX','707 N. 3rd St. Suite 130, Phoenix, AZ 85004',33.49294473050696296,-112.0630364545990289,NULL,'https://www.cahokiaphx.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','nonprofit_org','Cahokia PHX is a nonprofit organization based in Phoenix, Arizona, that is dedicated to cultural innovation and social impact. The organization is indigenous-led and seeks to create a brave cultural space for collaboration, innovation, and cultural collaboration. Their mission is to increase the collective wealth of underserved populations and activate a solidarity economy. They serve social entrepreneurs and underserved populations, particularly Black, Brown, and Indigenous communities. They distinguish themselves by transforming spaces into hubs of cultural expression and economic opportunity through gallery exhibitions, pop-up markets, product creation lines, live performances, and creative-led workshops.','["Gallery exhibitions","Pop-up markets","Product creation lines","Live performances","Creative-led workshops"]','cultural innovation, social impact, indigenous-led, social entrepreneurs, underserved populations, gallery exhibitions, pop-up markets, product creation lines, live performances, creative-led workshops','completed','2025-08-25T00:33:53.349Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Indigenous-led cultural innovation and social impact"}',NULL,NULL,NULL);
