INSERT INTO businesses VALUES('20217977-a798-4eef-8432-a2719ad6ae50','Capital Farms Meats & Provisions','410 W Wickenburg Way, Wickenburg, AZ 85390',33.96591980000000177,-112.735122000000004,'9286712060','Capitalfarms.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Capital Farms Meats & Provisions is a premium beef provider based in Wickenburg, Arizona. They specialize in Corriente Beef, a grass-fed variety known for its superior taste and quality. The business serves a broad customer base, including individual consumers and restaurants, offering a range of products from ground beef and hot dogs to specialty cuts and steaks. They distinguish themselves by raising their cattle locally on their own ranch, ensuring the quality and traceability of their products. Additionally, they offer a ''Build a Box'' service, allowing customers to customize their orders according to their needs.','["Ground Beef","Hot Dogs","Steaks","Jerky","Specialty Cuts","Discount - Box Bundles","Provisions","Gifts & Gear","Bulk Beef","Build a Box"]','Corriente Beef, Grass Fed Beef, Premium Quality, Local Ranch, Customize Order, Ground Beef, Steaks, Specialty Cuts, Hot Dogs','completed','2025-08-25T00:09:55.590Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Premium Corriente Beef"}',NULL,NULL,NULL);
