INSERT INTO businesses VALUES('02da15fb-d6d4-475a-8644-b9a3a33f2ff8','Charity Plumbing','3928 W Villa Theresa Dr, Glendale, AZ 85308',33.65422499999999672,-112.1445755000000019,'6023994041','www.charityplumbingaz.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','home_services','plumbing_electrical','Charity Plumbing is a family-owned, full-service plumbing company based in Phoenix, Arizona. With over 18 years of experience in the plumbing industry, they offer a wide range of services to both residential and commercial customers. They distinguish themselves by providing high-quality services at a fair price, being available 7 days a week for any emergency plumbing needs, and having experience with all major brands of plumbing hardware. Their services include general plumbing installations, plumbing repair, drain cleaning, bathroom repairs and renovations, water heater replacement, water softeners, reverse osmosis systems, water filtration, gas lines, whole home re-piping, hydro jetting, and trenchless sewer repair.','["General Plumbing Installations","Drain Cleaning","Bathroom Repairs and Renovations","Water Heater Replacement","Water Softeners","Reverse Osmosis Systems","Water Filtration","Gas Lines","Whole Home Re-piping","Hydro Jetting","Trenchless Sewer Repair"]','Plumbing, Drain Cleaning, Water Heater Replacement, Reverse Osmosis Systems, Water Filtration, Gas Lines, Hydro Jetting, Trenchless Sewer Repair','completed','2025-08-24T10:08:17.142Z','firecrawl','{"locally_owned":true,"specialty_focus":"Full-service plumbing"}',NULL,NULL,NULL);
