INSERT INTO businesses VALUES('0572ff13-e35f-43bc-b923-a834626bc449','Clever Koi','4236 N. Central Ave. #100, Phoenix, AZ 85012',33.4027727398285208,-112.0299669834529226,'602.222.3474','thecleverkoi.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','restaurant','Clever Koi is a restaurant that specializes in Asian cuisine, offering a variety of dishes inspired by regions such as Thailand, Korea, China, Vietnam, Japan, and Indo-China. It distinguishes itself by providing an ever-evolving menu of steamed buns, house-made dumplings, progressive noodle dishes, and small plates. The restaurant also features a bar program with a seasonal selection of bespoke drinks, built by award-winning mixologist and partner Joshua James. Clever Koi serves people who enjoy Asian cuisine and are looking for a unique dining experience in Phoenix and Gilbert, Arizona.','["Food service","Bar service","Catering service"]','Asian cuisine, restaurant, bar, steamed buns, house-made dumplings, noodle dishes, small plates, bespoke drinks, mixologist','completed','2025-08-24T10:14:47.378Z','firecrawl','{"locally_owned":true,"specialty_focus":"Asian cuisine"}',NULL,NULL,NULL);
