INSERT INTO businesses VALUES('25bd8e92-2327-4b95-92f9-e9e8141a5094','Cloth & Flame','734 W Polk St, Phoenix, AZ 85007',33.45342329999999719,-112.0830437999999987,'480-428-6028','https://clothandflame.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','catering','Cloth & Flame is a unique catering business based in Phoenix, Arizona, offering experiential dining experiences. They specialize in creating original events in various locations, including wilderness dinners and weekend-long retreats. Their offerings are not just about food but about the whole experience, including the design and location of the event. They serve a variety of clients, from individuals looking for a unique dining experience to corporations seeking brand events powered by experiences.','["Experiential Venues & Culinary Ticketed","Custom Corporate & Brand Events","Dinner at the Lavender Farm"]','experiential dining, event planning, catering, corporate events, wilderness dinners, culinary ticketed events','completed','2025-08-25T00:23:17.309Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Experiential dining and event planning"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('32cdbe22-8b31-4365-9d0a-4cdee72a8a08','Cloud 9 Salon Spa','8707 S. Priest Dr. #104, Tempe, AZ 85284',33.46306884059718811,-111.96044049004162,'480-598-3429','www.cloudninespa.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','beauty_personal_care','hair_salon','Cloud 9 Salon Spa is a beauty and personal care business located in Tempe, Arizona. They offer a wide range of services including haircuts, hair coloring, hair styling, and other salon services. In addition, they also provide spa services such as Swedish massage, therapeutic massage, hot stone therapy, and microblading. Their team of skilled stylists and professionals are dedicated to providing exceptional beauty and hair treatments. They distinguish themselves by providing a sophisticated salon ambiance, tailored beauty solutions, and a commitment to quality service.','["Hair Cuts","Hair Color","Hair Styling","Swedish Massage","Therapeutic Massage","Hot Stone Therapy","Microblading"]','Hair Salon, Spa, Haircuts, Hair Coloring, Hair Styling, Swedish Massage, Therapeutic Massage, Hot Stone Therapy, Microblading','completed','2025-08-25T00:52:33.619Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Hair and Spa Services"}',NULL,NULL,NULL);
