INSERT INTO businesses VALUES('0efc670b-1ad7-4b99-b44e-48435b13619d','Cloud Slingers - Downtown Chandler','1005 South Arizona Avenue Ste 11, Chandler, AZ 85225',33.31109533379355269,-111.8275692675264281,'(480) 590-2606','cloudslingers.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','electronics','Cloud Slingers is a vape shop with multiple locations across Arizona, serving people with vaping needs. It distinguishes itself by offering a comprehensive selection of vaping products, including mods, kits, e-liquids, and accessories. The shop is renowned for its in-house brands of e-liquids crafted in a certified laboratory, providing over 400 flavors of high-quality e-liquids at unbeatable prices. With a focus on customer satisfaction, Cloud Slingers offers expert guidance and personalized assistance to both seasoned vapers and those just starting out.','["mods","kits","e-liquids","vaping accessories"]','vape shop, e-liquids, vaping accessories, vaping products, in-house brands, customer satisfaction, expert guidance','completed','2025-08-24T10:34:17.363Z','firecrawl','{"locally_owned":true,"specialty_focus":"in-house brands of e-liquids"}',NULL,NULL,NULL);
