INSERT INTO businesses VALUES('150935d3-2134-47e6-b0ec-5d718b38ef1d','Coffee Pot Farms','PO Box 7335, Winslow, AZ 86047',33.44026762668496388,-112.0942360631423895,'(928) 613-7725','www.coffeepotfarms.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Coffee Pot Farms is a community-focused business that specializes in growing and providing fresh, nutritious vegetables for Navajo families. They operate on a Community Supported Agriculture (CSA) model, where customers make a mutual commitment with the farm, sharing in both the inherent risks and potential bounty of farm life. This unique model allows the farm to provide fresh produce while also fostering a strong community connection. They also have an online store and a pickup service for their produce.','["CSA membership","fresh vegetables","pickup service","online store"]','Community Supported Agriculture, fresh vegetables, Navajo families, online store, pickup service','completed','2025-08-24T10:46:36.455Z','firecrawl','{"locally_owned":true,"specialty_focus":"Community Supported Agriculture for Navajo families"}',NULL,NULL,NULL);
