INSERT INTO businesses VALUES('344e115a-993b-40a8-95a8-689feb757a86','Community Harvesters at Regenerating Sonora','PO Box 154, Superior, AZ 85173',33.42607200775547937,-112.0273497445755168,NULL,'https://regeneratingsonora.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','community_center','Community Harvesters at Regenerating Sonora is a community-oriented business based in Superior, Arizona. They aim to serve the local community by providing a platform for people to connect, share, and grow. The business name suggests a focus on sustainability and regeneration, indicating a commitment to environmental stewardship and community development. However, due to the lack of specific information available on their website, the exact nature of their services and offerings is unclear.','["Community services"]','Community, Harvesters, Regenerating, Sonora, Arizona, sustainability, community development','completed','2025-08-25T00:55:20.121Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Community development and sustainability"}',NULL,NULL,NULL);
