INSERT INTO businesses VALUES('25b57335-4960-40a4-ad04-a0652bd0d495','Community Library Sedona','3250 White Bear Road, Sedona, AZ 86336',34.86237580000000235,-111.8185832000000061,'928-282-7714','communitylibrarysedona.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','education_training','schools','Community Library Sedona is a public library located in Sedona, Arizona. It serves the local community by providing a wide range of services and resources. These include access to books, e-books, movies, and various online databases. The library also offers cultural passes, Tech2Go Chromebooks, and hotspots. It has a special focus on educational programs for kids and teens, with offerings such as STEAM activities and virtual programs. The library also provides helpful links for seniors and a Veterans History Project. It distinguishes itself by offering a variety of online resources and digital tools, including the YLN App, Libby, Kanopy, and Ancestry.com.','["Books","E-books","Movies","Online databases","Cultural passes","Tech2Go Chromebooks","Hotspots","Kids and Teens programs","Veterans History Project"]','library, education, books, e-books, movies, online databases, cultural passes, chromebooks, hotspots, kids programs, teen programs, senior resources, veterans history project','completed','2025-08-25T00:23:02.349Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Educational programs and digital resources"}',NULL,NULL,NULL);
