INSERT INTO businesses VALUES('28910124-44a6-4e1d-8793-ef9e8e55ce14','Cruz Farm','1226 E Jackrabbit Trl, AZ, AZ 85607',32.04965359999999919,-110.335602300000005,'5204011520','www.cruz.farm','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Cruz Farm is a multi-generational, Arizona-based farm that focuses on regenerative, sustainable, and organic practices. They serve a variety of customers, including food banks, restaurants, distributors, and individuals who value high-quality, locally grown, delicious foods. Cruz Farm distinguishes itself by its commitment to clean eating, non-GMO feed for animals, and avoidance of harmful chemicals, pesticides, and antibiotics. They offer a range of products including organic food boxes, pasture-raised eggs, Arizona pinto beans, and honey.','["organic food boxes","pasture-raised eggs","Arizona pinto beans","honey"]','organic farming, sustainable practices, pasture-raised eggs, Arizona pinto beans, non-GMO, locally grown food','completed','2025-08-25T00:28:05.178Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Organic and sustainable farming practices"}',NULL,NULL,NULL);
