INSERT INTO businesses VALUES('2325c324-f486-4992-acbb-529132efed35','DanceSport Education','604 E Balboa Dr, Tempe, AZ 85282',33.39799849999999993,-111.9306530000000067,'(480) 650-2312','https://www.dancesported.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','education_training','tutoring_training','DanceSport Education is a non-profit organization based in Tempe, Arizona, that offers a comprehensive dance program for children and youth aged 4-18. The program is designed to create positive, lifelong impacts on young people through participation in ballroom dance at their schools. The curriculum is delivered by world-class DanceSport professionals and is tailored to allow students to grow, learn, enrich, and achieve as they participate. The program also includes specially-designed annual dance events, Spring and Summer Camps, Intensive Workshops, and Master Classes.','["Youth dance classes","Annual dance events","Spring and Summer Camps","Intensive Workshops","Master Classes"]','DanceSport Education, youth dance classes, ballroom dance, DanceSport professionals, dance events, dance camps, dance workshops, master classes','completed','2025-08-25T00:18:13.849Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"DanceSport Education"}',NULL,NULL,NULL);
