INSERT INTO businesses VALUES('29bb1ddf-815f-446a-a810-7d85f618d1db','Desert Mountain Insurance','2918 N. 67th Place, Scottsdale, AZ 85251',33.47506997318527055,-111.9187574118708426,'480-348-2200','desertmountaininsurance.com/contact/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','professional_services','insurance','Desert Mountain Insurance is a professional insurance service provider based in Scottsdale, Arizona. They offer a wide range of insurance services to both individuals and businesses, with a particular focus on healthcare professionals and facilities. Their services include professional liability, medical, dental, podiatric, chiropractic, advanced healthcare professionals, hospice, home health, medispa, healthcare facilities and services management liability, cyber/privacy, business property, general liability, workers compensation, employee dishonesty bonds, special event liability insurance, and various personal insurance options. They distinguish themselves by offering comprehensive insurance solutions tailored to the specific needs of their clients.','["Professional Liability","Medical Insurance","Dental Insurance","Podiatric Insurance","Chiropractic Insurance","Advanced Healthcare Professionals Insurance","Hospice Insurance","Home Health Insurance","MediSpa Insurance","Healthcare Facilities and Services Management Liability","Cyber/Privacy Insurance","Business Property Insurance","General Liability Insurance","Workers Compensation","Employee Dishonesty Bonds","Special Event Liability Insurance","Personal Home, Condo and Dwelling Insurance","Auto Insurance","Umbrella Insurance","Recreational Insurance","Flood Insurance","Earthquake Insurance"]','Professional Insurance Services, Liability Insurance, Healthcare Professionals Insurance, Business Property Insurance, Workers Compensation, Employee Dishonesty Bonds, Special Event Liability Insurance, Personal Insurance','completed','2025-08-25T00:31:02.281Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Healthcare Professionals and Facilities Insurance"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('21737948-6570-4510-b62d-271359c86a79','Desert Mountain Moringa and Microgreens','458 Phelps Dr, Clarkdale, AZ 86324',34.76653689999999842,-112.0590722000000027,'(928)2215126','https://dmmoringa.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Desert Mountain Moringa and Microgreens is a unique grocery market business based in Clarkdale, Arizona. They specialize in the cultivation and sale of Moringa and Microgreens, serving health-conscious individuals and those interested in organic, nutrient-rich food options. The business distinguishes itself by offering locally grown, organic products that are never sprayed with pesticides. They also provide educational resources about the Moringa tree and its benefits for wellness and health. Customers can purchase their products online or at local markets that the business attends several times a week.','["Moringa","Microgreens","Nursery Supply","BioStimulant"]','Moringa, Microgreens, organic, locally grown, health, wellness, nursery supply, Arizona','completed','2025-08-25T00:14:40.332Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Moringa and Microgreens cultivation and sale"}',NULL,NULL,NULL);
