INSERT INTO businesses VALUES('0b91c6ef-9f29-43cf-8455-5ae3ec1594dd','Discover Marana','11555 w Civic Center Dr, Marana, AZ 85653',32.44740790000000174,-111.2095302999999973,'5203821988','DiscoverMarana.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','arts_entertainment','recreation','Discover Marana is a comprehensive travel guide for Marana, Arizona, offering a variety of services to tourists and locals alike. It provides information about various activities, places to visit, and events happening in Marana. It distinguishes itself by providing detailed guides for outdoor adventures, local food and drink options, golf courses, spas and wellness centers, and local history. It also provides resources for event planning, including venue suggestions and service providers.','["Travel guide","Event planning resources","Local history information","Outdoor adventure guides","Food and drink recommendations"]','Marana travel guide, outdoor adventures, local food and drink, event planning, local history, golf, spas and wellness','completed','2025-08-24T10:28:10.253Z','firecrawl','{"locally_owned":true,"specialty_focus":"Marana, Arizona travel guide"}',NULL,NULL,NULL);
