INSERT INTO businesses VALUES('0e3c04fa-ce35-486c-abca-8a81dad53144','Eighty-Eight Acres','3939 E. Saint Catherine Ave, Phoenix, AZ 85042',33.38771580000000227,-111.9963237000000049,'480-525-7880','www.eightyeightacres.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','home_services','landscaping_lawn','Eighty-Eight Acres is a residential landscape design firm based in Phoenix, Arizona. They specialize in creating sustainable landscapes for homeowners in the valley. Their mission is to inspire connections between people and nature by turning rainwater into a resource, nourishing families with gardens, and providing habitats for native wildlife. They offer a variety of services at different price points, including landscape consultation, concept sketch, landscape masterplan, and additional services like construction observation, HOA approval, and maintenance plans. They are committed to creating a more beautiful, thriving environment for everyone to enjoy.','["Landscape Consultation","Concept Sketch","Landscape Masterplan","Construction Observation","HOA Approval","Maintenance Plans","Rebate Documentation","Plant List / Plant Selection"]','residential landscape design, sustainable landscape, rainwater harvesting, garden design, native wildlife habitat, Phoenix, Arizona','completed','2025-08-24T10:32:57.956Z','firecrawl','{"locally_owned":true,"specialty_focus":"sustainable residential landscape design"}',NULL,NULL,NULL);
