INSERT INTO businesses VALUES('165df30b-5baa-4400-aaf5-b7c3b498949d','Epicenter Agritopia','3150 E Ray Rd, Gilbert, AZ 85296',33.32343399999999889,-111.721861000000004,NULL,'https://epicenteratagritopia.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','other','multi_service','Epicenter Agritopia is a multi-service business located in Gilbert, Arizona. It serves as a vibrant community hub that combines dining, shopping, and living in a walkable urban setting. The business caters to locals and first-time visitors, offering a variety of experiences from curated restaurants and retailers to elevated loft living. The Epicenter distinguishes itself by providing a unique shopping experience with curated boutiques, local favorites, and one-of-a-kind finds. It also hosts live music and pop-up events, adding to the dynamic and engaging atmosphere of the community.','["Dining options","Shopping outlets","Loft living","Live music and events"]','community hub, dining, shopping, urban living, curated restaurants, retailers, loft living, boutiques, live music, pop-up events','completed','2025-08-24T10:50:14.755Z','firecrawl','{"locally_owned":true,"specialty_focus":"Creating a vibrant community hub combining dining, shopping, and living"}',NULL,NULL,NULL);
