INSERT INTO businesses VALUES('2190cc15-8101-42dc-84d8-f66f369458e6','Equality Maricopa','2411 W 14th St, Tempe, AZ 85281',33.41285119999999865,-111.9757668999999965,'602-787-6867','https://equalitymaricopa.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','nonprofit_org','Equality Maricopa is a nonprofit organization dedicated to supporting LGBTQIA+ college students across Arizona. They aim to foster a culture of acceptance, equality, and inclusion while empowering students to succeed academically, personally, and professionally. They are committed to breaking down systemic barriers by providing funding, resources, and community support. They offer trainings, workshops, and resources that raise awareness of LGBTQIA+ issues and promote inclusive practices within Arizona’s higher education institutions. They also provide scholarships and emergency grants to help students overcome obstacles and thrive in their academic journeys.','["Scholarships","Emergency grants","Training","Workshops","Community support"]','nonprofit, LGBTQIA+ support, college students, scholarships, workshops, community support, Arizona','completed','2025-08-25T00:14:57.244Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"LGBTQIA+ college students support"}',NULL,NULL,NULL);
