INSERT INTO businesses VALUES('20f3d6fe-b609-4802-a33d-a5541a68a626','Farmyard','4056 E Weldon Ave, Phoenix, AZ 85018',33.49067000000000149,-111.9928445000000039,'(602) 954-1440','https://myfarmyard.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','home_services','landscaping_lawn','Farmyard is a landscaping business specializing in organic edible gardening in the Southwest. They serve individuals and schools who are interested in establishing their own edible gardens. Farmyard distinguishes itself by focusing on organic and local practices, offering services such as installation of raised garden beds and vegetable gardens, garden consulting, and maintenance. They use their own blend of local compost and organically grown heirloom seedlings and seeds. They also strongly advocate for the ''buy local'' food movement, promoting the idea of growing food in one''s own yard.','["garden installation","garden consulting","maintenance","edible school yards","composting","landscape architect design"]','organic gardening, edible gardening, garden consulting, garden installation, local compost, heirloom seedlings, Southwest gardening, buy local','completed','2025-08-25T00:12:56.235Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"organic edible gardening"}',NULL,NULL,NULL);
