INSERT INTO businesses VALUES('33817ac6-17db-44eb-8a85-b57d151f3ad9','Fashionably Green 1','P.O. Box 13333, Phoenix, AZ 85002',33.46068975220914865,-112.0262909375896783,'609-889-4895','https://fashionablygreen1.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','clothing_fashion','Fashionably Green 1 is a vintage and eco-friendly fashion retailer based in Phoenix, Arizona. They offer a wide range of sustainable fashion items and accessories for both men and women. The business distinguishes itself by providing a unique blend of vintage and modern fashion pieces, with a strong emphasis on sustainability and eco-friendliness. Their offerings include vintage clothes, dresses, footwear, handbags, and accessories. They also offer a range of vintage items for men, including clothes, footwear, and accessories.','["Women''s Vintage Clothes","Men''s Vintage Clothes","Vintage Footwear","Vintage Handbags","Vintage Accessories"]','vintage fashion, sustainable fashion, eco-friendly, men''s vintage, women''s vintage, accessories, footwear, handbags','completed','2025-08-25T00:54:10.179Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"vintage and sustainable fashion"}',NULL,NULL,NULL);
