INSERT INTO businesses VALUES('3035d5d6-1657-4bdc-a4d6-b0a8f14ad182','Flinn Foundation','1802 N. Central Ave, Phoenix, AZ 85004',33.46784730000000251,-112.0749820999999998,'(602) 744-6800','https://flinn.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','charitable_foundation','The Flinn Foundation is a privately-endowed philanthropic foundation established in 1965 with the mission to improve the quality of life in Arizona for future generations. It distinguishes itself by focusing on four key areas: advancing Arizona’s bioscience sector, enhancing undergraduate education for high-achieving students at the state’s public universities, improving the financial and creative health of Arizona’s arts and culture organizations, and strengthening civic life and state-level civic leadership in Arizona. The foundation also provides no-cost meeting space to Arizona nonprofits.','["Grantmaking","Flinn Scholars program","Arts and Culture program","Civic Leadership program","Bioscience program","Conference Center"]','Flinn Foundation, philanthropic foundation, bioscience, undergraduate education, arts and culture, civic leadership, Arizona','completed','2025-08-25T00:45:36.803Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Improving quality of life in Arizona through various programs and initiatives"}',NULL,NULL,NULL);
