INSERT INTO businesses VALUES('1121a77d-f032-47ba-be04-b8a273131d16','Flower Street Urban Gardens','4401 E Flower St, Phoenix, AZ 85018',33.4857640000000032,-111.986581000000001,'602-327-6560','flowerstreeturbangardens.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','home_services','landscaping_lawn','Flower Street Urban Gardens is a home services business specializing in landscaping and lawn care, with a unique focus on vertical gardening. They serve gardeners and aspiring gardeners in Arizona, aiming to make gardening a practical and fulfilling experience for all. Their unique selling point is their patented system for vertical gardening, which is perfect for small spaces like townhouse ''yards''. All their products are sourced in the USA and hand-crafted in Arizona. They also provide education about soil and plants, making gardening accessible to everyone.','["Vertical garden solutions","Gardening instructions","Gardening videos","Gardening products"]','vertical gardening, urban gardens, Arizona, hand-crafted, USA sourced, patented system, gardening education','completed','2025-08-24T10:39:30.162Z','firecrawl','{"locally_owned":true,"specialty_focus":"Vertical gardening solutions and education"}',NULL,NULL,NULL);
