INSERT INTO businesses VALUES('24a81d68-78ae-47a2-b1bc-5d65a4306b6c','Fluxx Productions','4400 E Broadway Blvd Suite 114, Tucson, AZ 85711',32.23924703296723492,-110.9857843867303018,'520-304-2155','www.fluxxproductions.org','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','arts_entertainment','theater_performance','Fluxx Productions is a theater production company based in Tucson, Arizona, with a strong focus on empowering LGBTQ+ communities, particularly Queer, Trans, Black, Indigenous, and People of Color (QTBIPOC). They use arts, activism, and mutual aid to create safe, inclusive spaces that celebrate diversity, amplify marginalized voices, and inspire social change. Their ultimate goal is to establish a queer cultural center that houses other nonprofits and community programs, providing a safe and empowering space for Tucson''s LGBTQ+ community. They acknowledge the ancestral territory of the Tohono O''odham and Yaqui peoples where they operate.','["Theater productions","Community events","Art shows","Poetry and open mic nights","Dance performances","Community gatherings"]','theater production, LGBTQ+ empowerment, QTBIPOC, arts, activism, mutual aid, queer cultural center, nonprofit, community programs, Tohono O''odham, Yaqui','completed','2025-08-25T00:20:52.626Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Empowering LGBTQ+ communities through arts and activism"}',NULL,NULL,NULL);
