INSERT INTO businesses VALUES('270ab00f-21a5-454e-a518-e6afd6e6b585','Fresh Blenz','3324 E Ray Rd #54, Gilbert, AZ 85236',33.32182279999999964,-111.7185434999999956,'682-219-2029','www.vercamaes.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','cafe','Fresh Blenz is a cafe type of business located in Gilbert, Arizona. They are known for their unique offerings, serving people with a taste for fresh and high-quality beverages. The business distinguishes itself by sharing Mom''s secret recipe with the world, indicating a strong focus on quality and tradition. Their offerings include a variety of bottled and concentrated beverages, with a focus on freshness and quality.','["Bottles","Gallons","Concentrated Bags"]','Fresh Blenz, cafe, fresh beverages, Mom''s secret recipe, bottled beverages, concentrated beverages','completed','2025-08-25T00:25:53.699Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Mom''s secret recipe beverages"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('3181355e-ff70-4120-9c7f-2d9224053530','Fresh Graphics','12449 W State Ave, Glendale, AZ 85305',33.54127239999999687,-112.327513499999995,'602-282-4121','Freshgraphicsagency.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','professional_services','marketing_advertising','Fresh Graphics is a marketing and advertising business based in Glendale, Arizona. The company specializes in creating thoughtful designs that help businesses grow and increase their branding. Fresh Graphics serves businesses of all sizes and is committed to bringing their clients'' ideas to life. They distinguish themselves by offering a three-step process that includes consultation, proofing, and finalizing, ensuring that the client is involved in every stage of the design process. Their services are designed to meet the unique needs of each client, providing them with designs that represent their company to its full capacity.','["Consultation","Proofing","Finalizing","Branding","Graphic Design"]','graphic design, branding, consultation, proofing, finalizing, professional designer, business growth','completed','2025-08-25T00:49:02.133Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Graphic Design and Branding"}',NULL,NULL,NULL);
