INSERT INTO businesses VALUES('19a4826a-e6b7-4469-92ba-028870c7dff1','Friends in Gasca Gardens (FIGG)','Warner and Bonarden, Tempe, AZ 85284',33.3867376087184411,-111.9513045298707681,NULL,'freshoffthevine-figg.blogspot.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','community_center','Friends in Gasca Gardens (FIGG) is a community garden based in Tempe, Arizona. It serves local residents who are interested in gardening, providing them with a space to grow their own plants and learn about different types of vegetation. The garden also hosts a variety of events, such as book clubs and gardening workshops, and collaborates with other local institutions like the Tempe Public Library. FIGG distinguishes itself by fostering a strong sense of community among its gardeners and promoting sustainable, local agriculture.','["Community garden plots","Gardening workshops","Book club","Gardening resources"]','community garden, gardening, local agriculture, sustainable farming, gardening workshops, Tempe, Arizona','completed','2025-08-24T10:54:43.009Z','firecrawl','{"locally_owned":true,"specialty_focus":"Community gardening and local agriculture"}',NULL,NULL,NULL);
