INSERT INTO businesses VALUES('14a19ba2-d269-41fe-8bf2-4dccf50d1640','Friends of Tucson''s Birthplace','946 W Mission Ln, Tucson, AZ 85745',32.21415999999999969,-110.9876435999999985,'(520) 955-5200','www.missiongarden.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','nonprofit_org','Friends of Tucson''s Birthplace is a nonprofit organization dedicated to preserving and promoting Tucson''s agricultural heritage. They manage the Mission Garden, a living agricultural museum that showcases Sonoran Desert-adapted heritage fruit trees, traditional local heirloom crops, and edible native plants. The organization offers a variety of programs and classes, and encourages community involvement through volunteering and gifting. They also provide educational resources such as a reference library and an education blog. The garden is located at a site sacred to the Tohono O’odham, adding a cultural and historical significance to their work.','["Public Programs & Classes","Volunteer Docent Program","Gifting to Mission Garden","Education Blog","Reference Library"]','nonprofit, agricultural heritage, Mission Garden, Sonoran Desert plants, heirloom crops, educational programs, volunteering, Tohono O’odham','completed','2025-08-24T10:45:33.509Z','firecrawl','{"locally_owned":true,"specialty_focus":"Preserving and promoting Tucson''s agricultural heritage"}',NULL,NULL,NULL);
