INSERT INTO businesses VALUES('0a44a27f-b68d-44e5-a2f9-809d5caf4119','Frites Street','7621 E Gray Rd, Scottsdale, AZ 85260',33.46698878982677883,-111.9661116212930949,'480-612-2872','https://www.fritesstreet.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','food_dining','catering','Frites Street is a specialized food business based in Scottsdale, Arizona, that caters to chefs and food enthusiasts with a variety of gourmet potato products. They distinguish themselves by providing naturally vegan, soy-free, gluten-free, and kosher Kennebec-style potato products. Their products are made by chefs, for chefs, and they aim to make superior potato products accessible to every chef and eater in America. Frites Street takes the classic preparation of using thick-cut, double-fried French fries to the next level, elevating pomme frites to the center of attention.','["1/4 Inch Fries","3/8 Inch Fries","1/2 Inch Fries","3/4 Inch Fries","Crinkle-Cut French Fries","Cottage Fries","3/4 Home Fries","Cowboy Potato Chips"]','Frites Street, gourmet potato products, Kennebec-style potatoes, vegan, soy-free, gluten-free, kosher, catering, Scottsdale, Arizona','completed','2025-08-24T10:25:54.444Z','firecrawl','{"locally_owned":true,"specialty_focus":"Gourmet Kennebec-style potato products"}',NULL,NULL,NULL);
