INSERT INTO businesses VALUES('0d254cc7-8d2d-43c7-a9fe-1531eed63a2f','GD2 Garden (Midtown)','Near Swan & Grant, Tucson, AZ 85712',32.22189656006143821,-111.0073067377241216,NULL,'https://communitygardensoftucson.org/community/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','community_center','GD2 Garden is a community garden located in Tucson, Arizona. It serves the local community by providing a space for people to grow their own food, learn about gardening, and connect with each other. The garden is part of the Community Gardens of Tucson, a nonprofit organization that manages several community gardens across the city. GD2 Garden distinguishes itself by hosting community events, such as the Community Dinner, where locals are invited to bring a dish and meet new people. It also offers plot rentals and reservations for those interested in starting their own garden.','["community garden plots","garden resources","community events"]','community garden, plot rentals, community dinner, gardening, Tucson','completed','2025-08-24T10:31:50.938Z','firecrawl','{"locally_owned":true,"specialty_focus":"community gardening"}',NULL,NULL,NULL);
