INSERT INTO businesses VALUES('14deb2e9-60bd-41c8-9690-4e3d297b3783','Generous','2225 North Gemini Drive, Suite W3 Mailbox 18, Flagstaff, AZ 86001',35.24269155562346611,-111.6328759430502374,'928-298-5938','https://meetgenerous.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','technology','software_development','Generous is a software development business that specializes in creating an AI-powered gifting application. The application is designed to serve individuals who want to automate their gift-giving process and never miss an important occasion again. The unique aspect of Generous is its AI-powered recommendation engine that personalizes gift ideas based on the recipient’s preferences, past gifts, and current trends. Additionally, it offers features like Autogift, which can remember events, suggest gifts, and even place orders on behalf of the user.','["AI-powered gifting app","Event reminder service","Gift recommendation","Autogift service"]','AI-powered gifting, gift automation, personalized gift ideas, event reminders, Autogift','completed','2025-08-24T10:46:05.544Z','firecrawl','{"locally_owned":true,"specialty_focus":"AI-powered gifting application"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('1ec89d36-f6b2-4875-9416-d8a09051db73','Genrose Insurance','9318 n 95th Way STE A-208, Scottsdale, AZ 85258',33.51902325886413792,-111.9698784061164928,'4804560327','https://www.genroseinsurance.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','professional_services','insurance','Genrose Insurance is an independent insurance brokerage based in Scottsdale, Arizona. They serve individuals, families, and businesses throughout the state with a variety of insurance needs. They distinguish themselves by working as brokers, representing the client rather than the insurance carrier. They offer a wide variety of insurance choices from reputable insurance carriers, and their relationships with these companies allow them to shop for a policy that meets the client''s coverage needs and budget. They pride themselves on offering expert advice, extensive choices, and superior customer service.','["Personal Insurance","Business Insurance","Life & Health Insurance","Specialty Insurance"]','insurance broker, independent insurance, Arizona insurance, personal insurance, business insurance, life and health insurance, specialty insurance','completed','2025-08-25T00:06:29.537Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Independent insurance brokerage"}',NULL,NULL,NULL);
