INSERT INTO businesses VALUES('25e205d0-2d51-4d8b-ba14-68f4d7b45333','Go With The Flow','6801 N 21st Ave Suite J, Phoenix, AZ 85015',33.46422888212267565,-112.1184613643177243,'6025267110','www.gowiththeflowaz.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','nonprofit_community','nonprofit_org','Go With The Flow is a nonprofit organization based in Arizona that aims to combat period poverty by providing menstrual hygiene products to students in need. Founded in 2017, the organization has since provided over 50,000 period packs to schools in Tucson, Phoenix, and neighboring areas. These packs, which contain tampons, pads, and panty liners, are made available to students at no cost to the school. The organization''s mission is to ensure that no student''s education is disrupted due to lack of access to essential menstrual items.','["Distribution of period packs to schools","Community partnership programs","Donation drives"]','period poverty, menstrual hygiene products, nonprofit, education, Arizona, period packs','completed','2025-08-25T00:23:35.018Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Addressing period poverty in schools"}',NULL,NULL,NULL);
