INSERT INTO businesses VALUES('1eb701c3-3be2-4249-996e-469aef42d857','Good Form Foods','659 E Main St, Mesa, AZ 85203',33.41501879999999858,-111.8166721999999993,'815-931-8264','www.goodformfoods.com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Good Form Foods is a health-focused grocery business that specializes in the production and sale of sprouted walnut butter. Serving individuals who value their health and seek convenience without compromise, Good Form Foods offers a unique, nutritious product that is handmade and contains no added sugars. Their flagship product, the sprouted walnut butter, is soaked and sprouted in Himalayan salt water and dried at a low temperature, a process that takes 48 hours. This process not only enhances the flavor but also the nutritional profile of the product. The business distinguishes itself by its commitment to providing a guilt-free indulgence that aligns with clean, nutritious dietary needs.','["Sprouted Walnut Butter: Original","Sprouted Walnut Butter: Vanilla Frosting","Sprouted Walnuts","Starter Bundle"]','sprouted walnut butter, health-focused grocery, no added sugars, handmade, nutritious','completed','2025-08-24T23:59:40.766Z','firecrawl','{"locally_owned":true,"specialty_focus":"sprouted walnut butter"}',NULL,NULL,NULL);
