INSERT INTO businesses VALUES('349f4231-aa7b-4b4b-96c4-40b778361032','Grand Canyon Adventures','PO BOX 875, Flagstaff, AZ 86001',35.19718563182115645,-111.6495022588124044,'(928) 440-5079','www.dothecanyon.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','arts_entertainment','recreation','Grand Canyon Adventures is a top-rated tour agency operating in Arizona, offering a variety of guided tours to iconic landscapes in the American Southwest. They serve tourists and locals alike who are interested in exploring the natural wonders of the region. They distinguish themselves by offering both public and private tours, including multi-day tours and team-building workshops for corporations. Their tours cover a range of attractions including the Grand Canyon, Antelope Canyon, Horseshoe Bend, and Sedona, among others. They also offer shuttle services and hotel pickup for added convenience.','["Grand Canyon Guided Tour","Antelope Canyon & Horseshoe Bend Tour","Private Tours","Grand Canyon Hiking Tours","Flagstaff Monuments Tour","Sedona Day Tour","Custom Private Tours","Team-Building Workshop","Corporate Tours","Multi-Day Tour","Shuttle Services"]','Grand Canyon Tours, Sightseeing Tours, Private Tours, Hiking Tours, Team-Building Workshop, Multi-Day Tour, Antelope Canyon, Horseshoe Bend, Sedona','completed','2025-08-25T00:55:48.973Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Guided tours to iconic landscapes in the American Southwest"}',NULL,NULL,NULL);
