INSERT INTO businesses VALUES('1eb8f7b9-1069-45c4-8b19-40d3e90431ec','Grand Canyon Spice Co.','2572 N Road 1 E, Chino Valley, AZ 86323',34.78343180000000245,-112.447488100000001,'928-433-6648','gcspice.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:31','2025-08-11 18:48:31','retail_shopping','grocery_market','Grand Canyon Spice Co. is a specialty spice and food company based in Chino Valley, Arizona. They are dedicated to creating flavorful smoked spices, blends, rubs, nuts, and other foodstuffs with the old-world flare of the artisanal Smokehouse. Their unique approach to infusing true wood smoke flavor into the core ingredients sets them apart in the market. Their products are versatile and can be used in a variety of dishes, from meats to soups, sauces, and vegetables. They also offer custom blend creation for restaurants.','["Smoked Spices","Blends","Rubs","Nuts","Custom Blend Creation"]','smoked spices, food company, artisanal smokehouse, custom blend, smoke flavor','completed','2025-08-24T23:59:49.687Z','firecrawl','{"locally_owned":true,"specialty_focus":"smoked spices and foodstuffs"}',NULL,NULL,NULL);
