INSERT INTO businesses VALUES('10f8f9c0-fc98-41b3-b460-e1e7ea9f6d4f','green bin - moving box rental','Phoenix AZ, US, Phoenix, AZ ',33.43284870000000097,-112.0067915000000056,'(602) 688-9956','rentgreenbin.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','transportation_logistics','moving_storage','Green Bin - Moving Box Rental is a moving and storage business based in Phoenix, AZ. They offer an eco-friendly alternative to traditional cardboard moving boxes. Their focus is on providing excellent customer service and reducing the environmental impact of moving. They deliver their reusable Green Bins to customers, who pack their belongings and then have the bins picked up once they''re done. The company also has a partnership with kathy ireland® Worldwide, which gives customers confidence in the quality of their service. Additionally, they plant a tree for every order placed, further emphasizing their commitment to sustainability.','["Green Bin rental","Delivery and pick-up service","Tree planting with every order"]','moving box rental, eco-friendly, reusable moving boxes, customer service, sustainability, kathy ireland® Worldwide, tree planting','completed','2025-08-24T10:38:54.870Z','firecrawl','{"locally_owned":true,"specialty_focus":"Eco-friendly moving solutions"}',NULL,NULL,NULL);
