INSERT INTO businesses VALUES('0293ebd1-a054-4ad9-b6b0-84ebf4c7bc49','Greenwood Brewing','922 N 5th St, Phoenix, AZ 85004, Phoenix, AZ 85004',33.49109256501068898,-112.0925922093651081,'(602) 875-8577','https://greenwoodbrews.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','brewery_winery','Greenwood Brewing is a woman-owned brewery located in Phoenix, Arizona. They pride themselves on creating approachable craft beer, welcoming all guests into their taproom, and making them feel at home. Greenwood Brewing started in a garage and grew into a full-fledged brewery, taproom, and beer garden. They host a variety of events, including trivia nights and homecoming weekends, and offer a wide selection of craft beers. They also provide a dog-friendly patio and encourage guests to bring their own food or enjoy food crafted by their neighbors.','["Craft beer","Private events","Taproom","Beer garden","Outdoor event space"]','craft beer, woman-owned, brewery, taproom, beer garden, dog-friendly patio, Phoenix, Arizona','completed','2025-08-24T10:07:24.960Z','firecrawl','{"locally_owned":true,"specialty_focus":"Woman-owned brewery with a wide range of craft beers"}',NULL,NULL,NULL);
