INSERT INTO businesses VALUES('2afab3fe-5218-488b-a74c-d2cd03f3a59d','Guided Meditations','750 W Orange Grove Road #9205, Tucson, AZ 85704',32.21424988088207896,-110.9525639441598202,'5204711859','Guidedmeditations.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','health_wellness','mental_health','Guided Meditations is a mental health business based in Tucson, Arizona. They specialize in providing guided meditation services to individuals seeking mental peace and wellness. Their unique approach to mental health involves using meditation techniques to help their clients achieve tranquility and balance in their lives. The business distinguishes itself by offering personalized guided meditation sessions, tailored to the individual needs of their clients.','["personalized guided meditation sessions"]','guided meditation, mental health, wellness, personalized sessions, Tucson','completed','2025-08-25T00:35:14.436Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"guided meditation"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('003d9d0c-f3b8-4d6f-93fb-acfed8a1cd31','Guitar Pickers','2302 N Scottsdale Rd, Scottsdale, AZ 85257',33.80300470000000245,-111.9277792000000033,'6023501818','GuitarPickersaz.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','electronics','Guitar Pickers is a guitar retail business based in Scottsdale, Arizona. They specialize in offering a wide variety of guitars including acoustic, electric, and bass guitars. They also provide guitar repair services. The business is independently owned and operated, and has been serving the local community since 2012. They have the largest collection of vintage and pre-owned guitars in all of Arizona. They distinguish themselves by offering a unique buying, selling, trading, and consigning experience for guitar enthusiasts. Their inventory is constantly changing, providing a unique selection for customers.','["Acoustic Guitars","Electric Guitars","Bass Guitars","Guitar Repairs"]','Guitar Retail, Acoustic Guitars, Electric Guitars, Bass Guitars, Guitar Repairs, Vintage Guitars, Pre-owned Guitars, Scottsdale, Arizona','completed','2025-08-24T10:02:17.284Z','firecrawl','{"locally_owned":true,"specialty_focus":"Vintage and Pre-owned Guitars"}',NULL,NULL,NULL);
