INSERT INTO businesses VALUES('07e8f975-b30b-422d-9914-70a0e329e93f','Habitat For Humanity Central Arizona','115 E. Watkins, Phoenix, AZ 85004',33.42580790000000234,-112.0850657000000012,'602 637 4763','habitatcaz.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','nonprofit_org','Habitat for Humanity Central Arizona is a nonprofit organization that provides affordable housing solutions for families in Central Arizona. They offer a variety of programs such as home repairs, neighborhood revitalization, aging in place, veteran services, and construction training. They also operate the Habitat ReStores, which are home improvement stores and donation centers that sell new and gently used furniture, appliances, home accessories, building materials and more to the public at a fraction of the retail price. Their mission is to bring people together to build homes, communities, and hope.','["Home Ownership","Emergency Home Repair","Aging in Place","Veterans Construction Training Program","Habitat ReStores"]','nonprofit, affordable housing, home repairs, neighborhood revitalization, veteran services, construction training, Habitat ReStores, donation centers','completed','2025-08-24T10:20:26.404Z','firecrawl','{"locally_owned":true,"specialty_focus":"affordable housing and home improvement"}',NULL,NULL,NULL);
