INSERT INTO businesses VALUES('30843ff9-1b1f-41ed-b8e2-488cfb887221','Hauser and Hauser Farms','652 Montezuma Castle Highway, Camp Verde, AZ 86322',34.57735089999999901,-111.8547741000000002,'(928) 567-2142','www.hauserandhauserfarms.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','Hauser and Hauser Farms is a family-owned farm located in Camp Verde, Arizona. They specialize in growing and selling sweet corn, alfalfa, and wheat hay. Their farm stand is open during the summertime and early fall, offering wagonloads of delicious sweet corn to the local community. They also provide alfalfa and wheat hay sales for delivery. Their commitment to conservation and stewardship sets them apart, ensuring each ear of corn is grown with care and perfection. They serve individuals who are looking for fresh, locally grown produce and businesses in need of hay for various purposes.','["Sweet corn","Alfalfa","Wheat hay"]','sweet corn, alfalfa, wheat hay, farm stand, locally grown, conservation, stewardship','completed','2025-08-25T00:46:16.032Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Growing and selling sweet corn, alfalfa, and wheat hay"}',NULL,NULL,NULL);
