INSERT INTO businesses VALUES('1e4e2bfa-1e44-4e64-acea-fcccbd78f8e6','Haws bees','710 e 2nd ave apt A, Mesa, AZ 85204',33.36895581128933231,-111.8177306239602018,'4802702159','Www.hawsbees.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','Haws Bees is a unique business based in Mesa, Arizona, specializing in bee rescue and honey production. They offer a variety of honey-based products, including raw honey and CBD-infused honey. They also provide bee rescue services for those who have unwanted bee colonies. Their mission is to save bees and educate the public about the importance of bees. They distinguish themselves by offering live bee rescues, school visits, and other educational services.','["Bee rescue","Raw honey","CBD-infused honey","Educational services"]','bee rescue, raw honey, CBD honey, educational services, bee colonies','completed','2025-08-24T23:58:57.307Z','firecrawl','{"locally_owned":true,"specialty_focus":"Bee rescue and honey production"}',NULL,NULL,NULL);
