INSERT INTO businesses VALUES('2b753cfb-32d0-4647-bd32-c1f36d606f8c','Heritage at Sportsman''s Park','9600 W. Sportsmans Park South, Glendale, AZ 85305',33.55080248708406998,-112.2354522822991498,'425-442-2634','https://www.heritageatsportsmanspark.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','arts_entertainment','event_venue','Heritage at Sportsman''s Park is a premier outdoor event venue located in Glendale, Arizona. They offer a full experience for creating unforgettable memories with panoramic views of the Valley. The venue is equipped with a fully-functional kitchen and state-of-the-art audio/visual capabilities. They also feature a Beer Garden with flexible seating, customizable lounge areas, fire pits, and misters, making it perfect for events of any size all year round. They are also a popular destination for pre-game entertainment during Cardinals home games. Their location, surrounded by Sportsman''s Park, provides complimentary event spaces, open parking, and a vast lawn.','["Event hosting","Pre-game entertainment","Food and beverage services","Audio/visual production","Event operations","Equipment rentals"]','event venue, outdoor venue, Cardinals pre-game, Beer Garden, Sportsman''s Park, Arizona events, panoramic views','completed','2025-08-25T00:36:54.510Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Outdoor event venue with pre-game entertainment"}',NULL,NULL,NULL);
