INSERT INTO businesses VALUES('25eab956-870d-4d46-b7be-8029d92e0925','Highland Vista Garden (Eastside)','5049 E Broadway, Suite 300, Tucson, AZ 85711',32.17869501693771639,-110.9467013335771952,'(520) 795-8823','https://communitygardensoftucson.org/gardenlocations/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','community_center','Highland Vista Garden is a community garden located in Tucson, Arizona. It serves the local community by providing a space for residents to grow their own plants and engage in gardening activities. The garden distinguishes itself by offering a variety of plots, both raised and in-ground, a pollinator plot, community herb garden, large compost system, and picnic tables. It also hosts community events such as poetry slams and porch concerts, fostering a sense of community and promoting interaction among residents.','["plot rentals","composting system","community herb garden","community events"]','community garden, Tucson, gardening, local community, plot rentals, composting, community events','completed','2025-08-25T00:23:44.566Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"community gardening and events"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('03f028f5-85ad-4cd9-aeb2-6cb2972f0830','Hilali Jewelry','1301 E Brill St, Phoenix, AZ 85006',33.46449549999999818,-112.0540558999999945,NULL,'https://www.hilalijewelry.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','gifts_novelty','Hilali Jewelry is a handcrafted jewelry business located in downtown Phoenix, Arizona. They specialize in creating all-gender statement jewelry using quality materials such as sterling silver, fine silver, 14K and 18K gold, solid brass, and natural gemstones. They ensure the durability of their products by soldering jump rings closed on every single piece. Hilali Jewelry is unique in its commitment to using no synthetic or lab-grown materials and no plated metals. Their offerings cater to people looking for unique, high-quality, handcrafted jewelry pieces.','["Handcrafted jewelry","Statement jewelry","Workshops"]','handcrafted jewelry, all-gender jewelry, sterling silver, fine silver, 14K gold, 18K gold, solid brass, natural gemstones, no synthetic materials, no plated metals, Arizona','completed','2025-08-24T10:10:33.346Z','firecrawl','{"locally_owned":true,"specialty_focus":"Handcrafted all-gender statement jewelry made from quality materials"}',NULL,NULL,NULL);
