INSERT INTO businesses VALUES('03791519-07df-4db5-9e3f-c2acfd77b5ff','Honoring Americas Veterans','6501 E. Greenway Parkway, 103-235, Scottsdale, AZ 85254',33.51499541116265135,-111.9598960787386658,'4807722934','https://honoringamericasveterans.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','nonprofit_org','Honoring Americas Veterans is a nonprofit organization dedicated to serving and honoring veterans in the United States. Based in Scottsdale, Arizona, the organization conducts a variety of programs and events, including the annual Phoenix Veterans Day Parade, to recognize the sacrifices of veterans. They also run the Heroes Veterans Program and organize commemorative events on Memorial Day and Pearl Harbor Day. Their mission is to inspire, connect, and honor veterans, and they have been recognized for their commitment with the prestigious Copper Eagle Award.','["Phoenix Veterans Day Parade","Heroes Veterans Program","Memorial Day events","Pearl Harbor Day events"]','veterans, nonprofit, parade, heroes, Memorial Day, Pearl Harbor Day, Phoenix, Arizona, Copper Eagle Award','completed','2025-08-24T10:10:02.403Z','firecrawl','{"locally_owned":true,"specialty_focus":"veteran services and recognition"}',NULL,NULL,NULL);
