INSERT INTO businesses VALUES('1d67704c-f4ef-40ef-a1b8-0173797a922a','IMG Event Rentals','9595 E Thunderbird Rd #3126, Scottsdale, AZ 85260',33.52632825649191516,-111.9263846579830925,'(602) 228-5440','https://www.rentimg.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','arts_entertainment','event_venue','IMG Event Rentals is a Scottsdale, Arizona-based event rental business that specializes in providing photo booth rentals for various types of gatherings. They are known for their high level of customer service and engagement during rentals, as well as their top-quality setups. They offer elite level equipment that minimizes wait time for instant prints, digital copies, or digital videos. They distinguish themselves by their commitment to ''Making Your Moment Iconic''. They cater to weddings, corporate events, and private parties, striving to make the photo booth rental experience fun for everyone involved.','["Instant Print Booth","Salsa iPad Booth","360 Video Booth","Wedding Rentals","Corporate Event Rentals","Private Event Rentals"]','photo booth rentals, event rentals, instant print booth, 360 video booth, Salsa iPad booth, wedding rentals, corporate events, private parties','completed','2025-08-24T23:56:29.612Z','firecrawl','{"locally_owned":true,"specialty_focus":"photo booth rentals"}',NULL,NULL,NULL);
