INSERT INTO businesses VALUES('0d5000e7-24d2-45c0-9c5b-fea71848cc43','Impact One','2473 S Higley Rd #104, Gilbert, AZ 85295',33.39621957300894195,-111.7808514964873155,'1-888 665-7465','https://impactone.pink/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','nonprofit_org','Impact One is a nonprofit organization based in Gilbert, Arizona, dedicated to supporting individuals impacted by breast cancer. They offer a variety of services and resources to assist patients during their treatment and recovery journey. The organization distinguishes itself by providing functional items to support physical and emotional recovery, offering breast cancer screening information, and providing education on breast health. They also offer Hope Boxes, which are shipped free of charge to the patient’s home and contain items to assist in the recovery process.','["Hope Boxes","breast cancer screening information","breast health education","functional recovery items"]','breast cancer support, nonprofit organization, breast health education, Hope Boxes, patient resources','completed','2025-08-24T10:32:00.141Z','firecrawl','{"locally_owned":true,"specialty_focus":"Breast Cancer Support and Education"}',NULL,NULL,NULL);
