INSERT INTO businesses VALUES('2547cc97-3f12-48dc-b165-9d18722f0037','InspirAction Ink','1900 W. Chandler Blvd. #15-220, Chandler, AZ 85224',33.32424309254883354,-111.8315793978096196,'(480) 227-0904','www.LoriSeverson.net','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','professional_services','consulting','InspirAction Ink is a consulting business focused on leadership coaching and personal development. It is led by Lori Severson, a coach, speaker, and author who works with highly conscious, successful women leaders to shift the inner game of leadership. Using her Harmonic Leadership framework, Lori guides leaders away from discord and into clarity, confidence, and aligned action. She helps leaders gain alignment with themselves, those they lead, and the organization, dispelling discord and increasing harmony and desired results. Lori''s approach is unique as it combines emotional intelligence, collaboration, and caring, which she believes are the characteristics of feminine intelligence and power.','["Leadership Coaching","Consulting Services","Author of ''An Unexpected Journey: One Woman’s Whale Tale''"]','Leadership Coaching, Consulting, Harmonic Leadership, Feminine Intelligence, Personal Development, Author','completed','2025-08-25T00:21:45.000Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Harmonic Leadership and Feminine Intelligence"}',NULL,NULL,NULL);
