INSERT INTO businesses VALUES('25eb793a-e800-457c-8837-0b3be8ccf9a4','International Raptor and Falconry Center','PO Box 1834, Flagstaff, AZ 86002',35.16091641456730343,-111.6416381678320989,'928-522-3472','www.raptorfalconrycenter.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','nonprofit_org','The International Raptor and Falconry Center is a nonprofit organization based in Flagstaff, Arizona, dedicated to the conservation and education of raptors. They serve the community by providing educational programs and hands-on experiences for all ages to learn about these apex predators. The center contributes to raptor conservation through research and rehabilitation, and also honors the culture of falconry by practicing it ethically and mentoring the next generation of falconers. They distinguish themselves by offering unique raptor and falconry experiences, community events, and outreach education programs.','["Raptor and Falconry Experiences","Community Events","Outreach Education Programs","Raptor Conservation","Rehabilitation"]','raptor conservation, falconry, education, nonprofit, community outreach, research, rehabilitation','completed','2025-08-25T00:23:56.025Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Raptor conservation and education"}',NULL,NULL,NULL);
