INSERT INTO businesses VALUES('1f762b5a-4474-4e77-8478-733ed53329c0','Just Roughin It Adventure Company','8658 E Shea Blvd. Ste 175, Scottsdale, AZ 85260',33.45562906970668137,-111.9000247428588893,'480-857-2477','www.justroughinit.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','clothing_fashion','Just Roughin It Adventure Company is a locally owned outdoor gear shop based in Scottsdale, Arizona. They specialize in providing new and pre-owned gear and apparel for hiking, camping, backpacking, and adventure travel. They also offer gear rentals, trip planning, and custom training programs for adventurers. Their unique focus is on curating brands and products specifically for the desert southwest, fostering a community of novice and expert adventurers alike. They also give back to the community by donating 1% of all sales to the National Forest Foundation.','["Outdoor Gear","Apparel","Gear Rentals","Trip Planning","Training Programs"]','outdoor gear, hiking, camping, backpacking, adventure travel, gear rentals, trip planning, training programs, desert southwest, National Forest Foundation','completed','2025-08-25T00:08:18.638Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Outdoor gear and apparel for the desert southwest"}',NULL,NULL,NULL);
