INSERT INTO businesses VALUES('1b56b3fd-4f85-4793-be87-94751e23af7a','KB Farm & Pantry','1730 E. Becker Lane Loop, Springerville, AZ 85938',33.49093757011757333,-112.0704485272499654,'(480) 369-0724','www.kbfarmandpantry.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','KB Farm & Pantry is a family-owned farm and pantry business that prides itself on raising top quality meat and dairy products. They serve customers who value quality, sustainability, and self-sufficiency. The business distinguishes itself by its commitment to quality and sustainability, with a focus on raising animals and producing products without cutting corners. They offer a variety of meats and dairy products, as well as food storage courses and equipment.','["Meats (beef, pork, lamb, chicken, turkey)","Dairy products (eggs)","Food storage guide","Food storage course","Wheat Grinder","Bosch Mixer","NutriMill Mixer","Freeze Dryer"]','family farm, sustainable farming, quality meats, dairy products, food storage, self-sufficiency','completed','2025-08-24T10:59:05.405Z','firecrawl','{"locally_owned":true,"specialty_focus":"Sustainable farming and food storage"}',NULL,NULL,NULL);
