INSERT INTO businesses VALUES('113342f1-0344-4145-9f3c-6dd27e599cbe','KD Design and Packaging','1210 W Alameda Dr #124, Tempe, AZ 85282',33.37885365349022493,-111.9278463446168388,'(480) 699-8808','www.KDDesignUSA.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','manufacturing_industrial','manufacturing','KD Design & Packaging is a custom packaging manufacturing business that serves both personal and commercial clients. They specialize in creating a variety of packaging materials such as cartons, boxes, counter displays, floor displays, foam packaging, custom signs, pallet wraps, and corrugated trays. They distinguish themselves by offering end-to-end solutions, from design conception to completion, and are equipped to handle projects of any size. Their state-of-the-art technology allows them to create high-quality, standout products without the need for costly printing plates or cutting dies.','["Custom Packaging","Cartons & Boxes","Counter Displays","Floor Displays","Foam Packaging","Custom Signs","Pallet Wraps","Corrugated Trays"]','custom packaging, digital printing, cutting technology, design, manufacturing, commercial packaging, retail packaging','completed','2025-08-24T10:39:59.060Z','firecrawl','{"locally_owned":true,"specialty_focus":"Custom packaging design and manufacturing"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('287e976d-bcb5-4e6c-aceb-178f7dc95caf','Keeling Garden (Midtown)','2919 N. Los Altos (near Ft Lowell and First Ave.), Tucson, AZ 85705',32.19083173431418032,-110.9676260594924884,NULL,'https://communitygardensoftucson.org/community/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','community_center','Keeling Garden (Midtown) is a community garden located in Tucson, Arizona. It provides a space for community members to engage in gardening activities, fostering a sense of community and promoting sustainable practices. The garden hosts various events such as Community Dinner, where attendees are encouraged to bring a dish and mingle with other community members. They also offer plot rentals and reservations for those interested in starting their own garden. Keeling Garden distinguishes itself by recognizing the historical injustices perpetrated upon the Indigenous people of the Tucson Basin and honoring their cultures and contributions.','["Community Dinner","Plot Rentals and Reservations","Start a New Garden"]','community garden, plot rentals, community dinner, sustainable practices, Tucson, gardening','completed','2025-08-25T00:27:55.862Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Community engagement through gardening"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('1ff5df26-67eb-4f12-b8fc-cca66e97cd07','Keeling Schaefer Vineyards','154 North Railroad Avenue, Willcox, AZ 85643',32.25266609999999901,-109.830994700000005,'520-824-2500','www.keelingschaefervineyards.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','brewery_winery','Keeling Schaefer Vineyards is a premium estate winery located in Willcox, Arizona. They specialize in producing Rhone-styled wines from their 29 acres of vineyards situated along Rock Creek on the western slope of the Chiricahua Mountains. Their wines have been featured and reviewed in various publications and have scored highly on Wine Spectator and Tastings.com. They control the quality of their wines from grape to glass, offering a wide variety of wine styles and varietals. They also offer wine tasting experiences in their historic downtown Willcox tasting room and participate in local wine festivals.','["Wine tasting","Wine sales","Wine club","Winery tours"]','Arizona Estate Wines, Rhone-styled wines, vineyard, wine tasting, wine festivals, Willcox','completed','2025-08-25T00:09:47.263Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Estate grown and bottled Rhone-styled wines"}',NULL,NULL,NULL);
