INSERT INTO businesses VALUES('2950c028-e9a5-4015-8c09-f91eb6f55817','Kino Learning Center','6625 N First Avenue, Tucson, AZ 85718',32.2228078997403955,-110.9776564393647079,'5202977278','kinoschool.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','education_training','schools','Kino Learning Center is a non-traditional school serving students from kindergarten through high school in Tucson, Arizona. The school is unique in its approach to education, focusing on fostering curiosity and excitement for learning in a cooperative and joyful environment. They believe that education is a lifelong process and that the world around us is a classroom. Kino Learning Center does not use traditional grade levels, instead grouping students into four main categories based on age range and developmental needs. The school also emphasizes community service, field trips, and apprentice work as integral parts of the learning experience.','["Primary education","Mid-Level education","Junior High education","High School education"]','non-traditional education, student-centered learning, multi-age homerooms, lifelong learning, community service, field trips, apprentice work','completed','2025-08-25T00:29:16.965Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"non-traditional, student-centered education"}',NULL,NULL,NULL);
