INSERT INTO businesses VALUES('1115bb76-6e25-44aa-8d36-5069a1ef1b40','Las Milpitas Community Farm','2405 South Cottonwood Lane, Tucson, AZ 85713',32.1949311999999992,-110.9902869999999951,'(520) 622-0525','https://www.communityfoodbank.org/Locations/Las-Milpitas','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','community_center','Las Milpitas Community Farm is a non-profit community center that focuses on promoting sustainable local food systems. Situated on a six-acre land in Tucson, Arizona, it provides materials, education, and support for local residents to grow food for themselves, with a particular emphasis on assisting low-income families. The farm serves as a unique community-building space where neighbors can gather, connect, learn, and share. Through workshops, work days, and partnerships with local schools, it also operates as an educational site that trains and builds leaders in desert food cultivation. The farm is part of the Community Food Bank of Southern Arizona and aims to bring residents from all areas of Tucson together to build community and create strong leaders who can advocate for a resilient, sustainable local food system.','["Community farming","Educational workshops","Gardening space","Leadership training","Community events hosting"]','community farm, sustainable local food system, desert food cultivation, low-income families support, educational site, community building','completed','2025-08-24T10:39:13.812Z','firecrawl','{"locally_owned":true,"specialty_focus":"Promoting sustainable local food systems and community building"}',NULL,NULL,NULL);
