INSERT INTO businesses VALUES('159428b8-cc88-436f-a770-8b0f79d1a110','Laura Chamberlin Professional Chef','7525 Derryberry Dr, Flagstaff, AZ 86004',35.17379202955710582,-111.6039317647258998,'(928) 814-8218','https://www.lcprofessionalchef.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','catering','Laura Chamberlin Professional Chef, operating under the name Culinary Concepts Southwest, is a catering and meal service business based in Flagstaff, Arizona. They specialize in event catering, farm-to-table dinners, weekly meals, and sports nutrition-specific menus for elite athletes. They are passionate about using local and seasonal ingredients and support local and regional farmers. Their services cater to a variety of needs, from individuals seeking ready-to-pick-up meals to groups needing catering for training events, film productions, and wilderness adventures.','["Event Catering","Farm-to-Table Dinners","Weekly Meals","Sports Nutrition Menus"]','catering, meal service, farm-to-table, sports nutrition, local ingredients, seasonal ingredients, event catering, weekly meals','completed','2025-08-24T10:48:13.346Z','firecrawl','{"locally_owned":true,"specialty_focus":"Farm-to-table meals and sports nutrition"}',NULL,NULL,NULL);
