INSERT INTO businesses VALUES('0200eca5-ae23-494a-b6d8-af0e608a7944','Laveen Brothers Beef','2901 E Camelback Rd, Phoenix, AZ 85016',33.50946619999999854,-112.0190245999999946,'(623) 600-8821','https://laveenbrosbeef.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','Laveen Brothers Beef is a family-owned beef company based in Arizona. They pride themselves on being a fully integrated business, overseeing the entire process from ''pasture to plate''. This ensures high-quality, fresh produce for their customers. Their unique selling point is their commitment to local, sustainable farming and providing customers with the best quality beef. They serve a wide range of customers, from families looking for quality meat products to restaurants and other food businesses in need of a reliable supplier.','["Beef products","Local delivery"]','beef, family-owned, Arizona, sustainable farming, pasture to plate, grocery, meat products','completed','2025-08-24T10:05:43.548Z','firecrawl','{"locally_owned":true,"specialty_focus":"Pasture to plate beef products"}',NULL,NULL,NULL);
