INSERT INTO businesses VALUES('1d9af38b-aa13-4ca3-8672-731dc6eac1e1','Lawrence Dunham Vineyards','13922 South Kuykendall Cutoff Road, Pearce, AZ 85625',33.4179739286611408,-112.0399910692432713,'602-320-1485','lawrencedunhamvineyards.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','brewery_winery','Lawrence Dunham Vineyards is a winery located in the Chiricahua Mountain foothills in Southeastern Arizona. They offer a variety of award-winning wines that are a direct reflection of the unique high-altitude terroir. The winery distinguishes itself by providing easy to apply wine tips to expand customers'' wine and food enjoyment. They also offer wine tasting experiences and have a wine club that customers can join. The business is named after the family names Lawrence and Dunham, with the V denoting their vineyard.','["Wine tasting","Wine club membership","Wine shop"]','winery, wine tasting, wine club, award-winning wines, high-altitude terroir, wine tips','completed','2025-08-24T23:57:05.723Z','firecrawl','{"locally_owned":true,"specialty_focus":"High-altitude terroir wines"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('245a2e79-31f3-40fb-9cd5-b91e4db1fece','Lazy 5S Cattle Company','19 N. Main Street, Cottonwood, AZ 86326',34.74055609999999917,-112.0096570000000042,'(602) 803-8121','https://lazy5scattlecompany.com/home','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','Lazy 5S Cattle Company is a cattle farming business located in Arizona that specializes in producing a variety of beef products. They offer grass-fed finished beef, brewers grain finished beef, and grain-fed beef. The company prides itself on raising beef without administered steroid drugs or hormones, with GMO-free feed, and without antibiotics. They offer different packages of beef, including whole, half, and quarter beef packages. The company distinguishes itself by offering custom cutting for whole beef orders and by supporting local charities.','["Grass Fed Finished Beef","Brewers Grain Finished Beef","Grain Fed Beef","Whole Beef Package","Half Beef Package","Quarter Beef Package"]','cattle farming, beef production, grass-fed beef, grain-fed beef, local beef, Arizona','completed','2025-08-25T00:20:15.011Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Grass-fed and grain-fed beef production"}',NULL,NULL,NULL);
