INSERT INTO businesses VALUES('04d56afc-1de3-4f7f-91e3-632841d014a8','Live Bearded','4700 N 40th St 101, Phoenix, AZ 85018',33.46815515122430896,-112.0298686048785868,'877-579-3620','https://livebearded.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','beauty_personal_care','barbershop','Live Bearded is a specialized grooming business dedicated to serving men who sport beards. They offer a variety of premium beard care products, aiming to help beardsmen look, feel, and be their best. Their products are made in the USA with natural ingredients and they offer a Better Beard Guarantee with 365-Day Returns. They distinguish themselves by providing a comprehensive range of beard care products, from beard oils, butters, washes, and conditioners to growth vitamins and derma roller kits. They also offer body care products and apparel.','["Beard Oil","Beard Butter","Beard Wash","Beard Conditioner","Leave-In Conditioner","Mustache Wax","Growth Vitamins","Derma Roller Kit","Derma Roller Growth Serum","Derma Roller Cleanser","Deodorant","Bar Soap","Body Wash","Utility Spray","Shirts","Hats"]','beard care, grooming, beard growth, natural ingredients, beard oil, beard butter, beard wash, beard conditioner, derma roller, body care, apparel','completed','2025-08-24T10:13:02.595Z','firecrawl','{"locally_owned":true,"specialty_focus":"beard grooming and care"}',NULL,NULL,NULL);
