INSERT INTO businesses VALUES('1dc34375-bdaf-4700-82c8-64ea5a3a752c','Local Buzz','21817 N 38th PL, Phoenix, AZ 85050',33.68450940000000316,-111.995092900000003,'(602) 741-1964','www.localbuzz.co','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','technology','web_development','LocalBuzz is a web-based platform that serves people with the need to discover local businesses, events, and organizations. It distinguishes itself by providing a unique way to explore towns, cities, and communities through videos. Users can find new restaurants, bands, experiences, and more, all while supporting local businesses. The platform also allows users to share their favorite posts, people, and places with friends worldwide, making it a truly personalized experience.','["local business discovery","community event discovery","personalized experience sharing"]','local discovery, community engagement, local businesses, video exploration, community support','completed','2025-08-24T23:57:22.393Z','firecrawl','{"locally_owned":true,"specialty_focus":"local business and event discovery through video content"}',NULL,NULL,NULL);
