INSERT INTO businesses VALUES('2581e8bf-f9ed-4c23-aefe-72212a5f40aa','Local First Community Kitchen - Mesa','659 E Main Street, Mesa, AZ 85204',33.41501879999999858,-111.8166721999999993,'602-956-0909','https://www.goodfoodfinderaz.com/community-kitchens','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','education_training','workshops_seminars','Local First Community Kitchen - Mesa is a food business incubator that provides a fully equipped and licensed space for food entrepreneurs looking to start or expand their operations. The business distinguishes itself by offering a two-year incubation program designed to take a business from its early operating stages to a full-fledged revenue generating business. They provide resources such as a large walk-in refrigerator, dry food storage, and dedicated wash area, as well as free WIFI and other business conveniences. They also offer a Good Food Boot Camp and assistance with food business certifications.','["Business incubation","Good Food Boot Camp","Food business certifications","Community Kitchen Incubator Application"]','food business incubator, community kitchen, food entrepreneurship, business incubation program, Good Food Boot Camp, food business certifications','completed','2025-08-25T00:22:13.327Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Food business incubation"}',NULL,NULL,NULL);
