INSERT INTO businesses VALUES('2b0be6ae-5dbd-4d31-b3ff-138c354ae0c8','Local Trade','2309 N 24th St Unit B, Phoenix, AZ 85008',33.43906727183409089,-112.0868613567458425,'(480) 580-4761','www.localtradeaz.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','Local Trade is a unique marketplace that brings together local makers, artists, and small business owners in Phoenix, Arizona. They offer a variety of products from home goods, art, furniture, clothing, jewelry, accessories, health & beauty items, to food and pet products. They distinguish themselves by creating a community-focused shopping experience that encourages self-sustainment and local support. They achieve this through online sales, pop-up markets, and home staging services. Their mission is to ''keep it local'' by empowering local makers and providing them with opportunities and tools to thrive.','["home goods","art","furniture","clothing","jewelry","accessories","health & beauty items","food products","pet products","pop-up markets","home staging"]','local makers, community-focused, Phoenix, home goods, art, furniture, clothing, jewelry, accessories, health & beauty, food, pets, pop-up markets, home staging','completed','2025-08-25T00:35:22.341Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"local makers and artists"}',NULL,NULL,NULL);
