INSERT INTO businesses VALUES('2bef92d8-cb49-4c28-a139-cafc4031a411','Lohman Company','1630 S. Stapley Dr., Suite 108, Mesa, AZ 85204',33.43538941436015221,-111.8486292869839644,'480-355-1100','www.lohmancompany.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','professional_services','accounting_tax','Lohman Company is a Certified Public Accounting and Professional Services firm based in Mesa, Arizona. Established in 2000, they serve a wide range of clients, including local businesses, companies across the United States, and entities with multi-state and international holdings. They offer comprehensive, strategic guidance that meets all areas of tax, consulting, and audit needs. Their unique Project Professionals service line supports clients in completing critical Project Accounting, Project Management, and Interim Finance and Accounting initiatives. The firm is committed to delivering a personalized, caring approach to each engagement, operating with high integrity, and striving to do the right thing for their clients, employees, and community.','["Tax Planning & Compliance","Assurance","Client Accounting Services","Mergers & Acquisitions","Business Advisory & Consultation","Project Professional Services"]','Accounting, Tax Planning, Compliance, Business Advisory, Consultation, Client Accounting Services, Mergers, Acquisitions, Project Professional Services','completed','2025-08-25T00:37:28.723Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Project Accounting, Project Management, and Interim Finance and Accounting initiatives"}',NULL,NULL,NULL);
