INSERT INTO businesses VALUES('1bbe921d-93ef-461d-a24c-0bfe2642f892','Lom Wong','218 E Portland St, Phoenix, AZ 85004',33.46020299999999992,-112.0704268000000071,'(602) 675-0522','https://www.lomwongaz.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','restaurant','Lom Wong is a Thai restaurant located in Phoenix, Arizona. The restaurant celebrates the diverse people and cultures of Thailand by cooking the types of food that one would find in villages and small towns across the different regions of the country. They are dedicated to maintaining the authenticity of the ingredients, techniques, and service styles that are typical in the villages and towns that inspired their concept. Lom Wong provides a unique dining experience by serving food as it''s ready, which is meant to be shared among diners, reflecting the communal dining culture of Thailand.','["Dinner","Natural Wine","Gift Cards","Reservations"]','Thai cuisine, regional cuisines of Thailand, authentic Thai food, Phoenix restaurant, communal dining','completed','2025-08-24T11:00:01.264Z','firecrawl','{"locally_owned":true,"specialty_focus":"Authentic regional cuisines of Thailand"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('07a9bb89-396a-4066-b547-097b0685bf36','Loma Prieta Pottery','6131 N Desert Willow Dr, Tucson, AZ 85743',32.19471005346759541,-110.9639754513682278,'5204377543','www.lomaprietapottery.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','gifts_novelty','Loma Prieta Pottery is a pottery studio based in Tucson, Arizona. The studio specializes in handcrafted functional stoneware and porcelain, created by Terry Parker. The pottery items are designed to be both aesthetically pleasing and practical for use. The studio is open to visitors most of the time, and video visits can also be arranged. The pottery items can also be purchased online through their Etsy shop. The business serves pottery enthusiasts and customers looking for unique, handcrafted items for their homes or as gifts.','["Handcrafted Stoneware","Handcrafted Porcelain","Functional Pottery"]','handcrafted pottery, stoneware, porcelain, functional pottery, Tucson, Arizona, Terry Parker, Loma Prieta Pottery, Etsy shop','completed','2025-08-24T10:19:35.791Z','firecrawl','{"locally_owned":true,"specialty_focus":"Handcrafted Functional Stoneware and Porcelain"}',NULL,NULL,NULL);
