INSERT INTO businesses VALUES('20d170f5-fe7e-485e-a8d4-7e8b556cddef','Lonely Angel Tattoos','300 E Congress St, Tucson, AZ 85701',32.22198600000000112,-110.9669339999999949,NULL,'https://www.instagram.com/lonelyangeltattoos/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','beauty_personal_care','tattoo_parlor','Lonely Angel Tattoos is a tattoo parlor located in Tucson, Arizona. They serve individuals who are looking to express themselves through body art. The business distinguishes itself by offering a wide variety of tattoo styles and designs, catering to the unique tastes and preferences of their customers. They are known for their professional service and high-quality work.','["Tattoo Services","Custom Tattoo Designs"]','Tattoo, Body Art, Tucson, Arizona, Lonely Angel Tattoos','completed','2025-08-25T00:12:03.169Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Custom Tattoo Designs"}',NULL,NULL,NULL);
