INSERT INTO businesses VALUES('16467a7e-629a-4f7b-8488-6b3e8d1f9a2e','Love Love Sweets','3935 E Rough Rider RD, 1312, Phoenix, AZ 85050',33.68800490000000281,-111.9881445000000042,'(646) 573-4657','https://lovelovesweets.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','bakery','Love Love Sweets is a unique bakery business located in Phoenix, Arizona. They specialize in creating vegan, plant-based desserts that are free from grains, gluten, refined sugar, agave, nuts, and preservatives. Their mission is to provide delicious and nourishing desserts that are good for the body and satisfy cravings. They use organic ingredients and unprocessed methods to create their products, ensuring that each dessert is packed with essential vitamins and minerals, and low in calories. Their offerings range from brownies and cakes to tarts and cookies. They also offer nationwide shipping and local pickup in the Phoenix Metro Area.','["Brownie Chocolate Cake","Pumpkin Tart","Vanilla Espresso Cake","Custom Party Cake","Swiss Roll","Pumpkin Mini Tarts","Mini Brownie and Vanilla Espresso","Cookies","Cupcakes"]','vegan desserts, plant-based, organic ingredients, unprocessed, Phoenix, Arizona, nationwide shipping, gluten-free, nut-free, sugar-free','completed','2025-08-24T10:49:45.542Z','firecrawl','{"locally_owned":true,"specialty_focus":"Vegan, plant-based desserts"}',NULL,NULL,NULL);
