INSERT INTO businesses VALUES('01b66171-6a51-463e-bfa5-6ab2ed6b19ed','Low Key Piano Bar','501 S Mill Ave Suite B101, Tempe, AZ 85281',33.40029019923473897,-111.9850529670199535,'480-355-1705','https://www.lowkeypianobar.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','arts_entertainment','music_venue','Low Key Piano Bar is a music venue located in Tempe, Arizona. It serves people who enjoy live music and entertainment, particularly those who appreciate the unique atmosphere of a piano bar. The business distinguishes itself by offering a lively, interactive musical experience where patrons can request songs and sing along with talented pianists. It is a popular destination for locals and tourists alike, offering a unique blend of entertainment, music, and social interaction.','["live music","entertainment","bar services"]','piano bar, live music, entertainment, Tempe, Arizona, interactive, song requests','completed','2025-08-24T10:05:31.628Z','firecrawl','{"locally_owned":true,"specialty_focus":"interactive piano bar"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('1b967eaf-f01d-4da9-8df2-def8a1e6b4da','Lowell Observatory','1400 W. Mars Hill Road, Flagstaff, AZ 86001',35.20294499999999971,-111.6646528999999929,'928-774-3358','lowell.edu','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','arts_entertainment','recreation','Lowell Observatory is a renowned astronomical observatory located in Flagstaff, Arizona. It serves a wide range of audiences including educators, researchers, and general public with an interest in astronomy. The observatory is known for its rich history, including being the site where Pluto was discovered. It offers a variety of experiences such as guided tours, stargazing, historical exhibits, and astrophotography courses. The observatory also hosts special events, camps, and venue rentals, making it a unique destination for both educational and recreational purposes.','["guided tours","stargazing","astrophotography course","historical exhibits","venue rentals","camps"]','astronomy, observatory, stargazing, astrophotography, educational tours, historical exhibits, Pluto Discovery','completed','2025-08-24T10:59:35.208Z','firecrawl','{"locally_owned":true,"specialty_focus":"astronomy and space research"}',NULL,NULL,NULL);
