INSERT INTO businesses VALUES('2a749e0d-16aa-4661-8e8e-d255a13dc982','Mariana De La Vega | Connecting Hearts & Minds','1918 E Prince Rd, Tucson, AZ 85719',32.27212829999999855,-110.9433527000000054,'520-392-6639','https://connectingheartsandminds.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','arts_entertainment','art_gallery','Mariana De La Vega | Connecting Hearts & Minds is an art gallery and transformation institute based in Tucson, Arizona. It offers a variety of services and programs aimed at healing the soul, connecting the mind and heart, managing stress and anxiety, and improving self-esteem. The business distinguishes itself by offering innovative techniques and practices such as Expressive Arts, HeartMath, Resilience, Mindfulness, and Positive Psychology. It hosts exhibitions and events that celebrate empowerment, resilience, and creativity, particularly focusing on the strength and brilliance of women.','["Programa TransformArte","Programa HeArtMath","Programa de Artes Expresivas","Conferencias y Talleres","Coaching individuales y grupales"]','art gallery, transformation institute, Expressive Arts, HeartMath, Resilience, Mindfulness, Positive Psychology, empowerment, resilience, creativity','completed','2025-08-25T00:33:25.680Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"empowerment and resilience through art and transformation programs"}',NULL,NULL,NULL);
