INSERT INTO businesses VALUES('0751caa4-7252-4746-ad69-49eb743752e5','Marksman Signing Agency','1453 N Dysart Rd STE106 #677, Avondale, AZ 85323',33.40822854507303674,-112.1097444067437437,'4808287771','www.MarksmanSigning.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','professional_services','legal_services','Marksman Signing Agency is a professional legal service provider located in Avondale, Arizona. They specialize in providing accurate and convenient services to lending institutions, corporations, and the general public by witnessing the signing of documents based on current legal requirements. They also offer mobile fingerprinting, bonds, and private wealth notarizations for the Phoenix Metro Area. Their mission is to be a good steward of the industry and a champion in expanding notary services that are handled in a safe, ethical, and legal manner. They have received positive reviews for their professionalism, efficiency, and preparedness.','["Messenger by Marksman","Finger Printing","BX Bond Exchange","Notary Services","All Wedding Things"]','Notary Services, Fingerprinting Services, Corporate Fingerprinting, Mobile Fingerprinting, Bonds, Private Wealth Notarizations','completed','2025-08-24T10:18:22.604Z','firecrawl','{"locally_owned":true,"specialty_focus":"Notary and Fingerprinting Services"}',NULL,NULL,NULL);
