INSERT INTO businesses VALUES('2720cc77-7648-4352-98ba-57b3553283bd','Martins Auto Repair','3636 N.16th.St., Phoenix, AZ 85016',33.41848689483439472,-112.099080432081891,'(602) 266-5755','martinsautorepair.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','automotive','auto_repair','Martin''s Auto Repair is a professional automotive repair and maintenance business serving the residents of Phoenix, Arizona, and surrounding areas since 1971. As a family-owned and operated auto repair shop, they provide high-quality automotive services for both foreign and domestic vehicles. They offer a wide range of services from routine maintenance to complex repairs, using the latest diagnostic tools and repair technology. They are a certified NAPA AutoCare Center, combining the benefits of a nationwide network with the personalized care of a local business. They also offer a complimentary shuttle service for their customers.','["Air Conditioning","Heating","Engine Cooling System","Fuel Injection","Oil Changes","Transmission","Brakes"]','Auto Repair, Maintenance, Phoenix, Automotive Services, NAPA AutoCare Center, Shuttle Service','completed','2025-08-25T00:26:21.278Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Automotive repair and maintenance"}',NULL,NULL,NULL);
