INSERT INTO businesses VALUES('1f404bb6-62f4-434a-8d93-13d42ee2e087','Mary Meredith/Duffy Garden (East)','755 N. Magnolia (Near 5th St & Swan), Tucson, AZ 85711',32.19297695340546995,-110.961198183722388,NULL,'https://communitygardensoftucson.org/community/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','community_center','Mary Meredith/Duffy Garden (East) is a community garden located in Tucson, Arizona. It serves as a hub for local residents to engage in gardening activities, learn about sustainable practices, and foster community connections. The garden distinguishes itself by hosting community dinners and other events, offering plot rentals and reservations, and providing resources for planting and garden maintenance. It also acknowledges and respects the historical injustices perpetrated upon the Indigenous people of the Tucson Basin, and celebrates their cultures and contributions.','["Community dinners","Garden plot rentals","Gardening resources"]','community garden, plot rentals, community dinner, gardening resources, Tucson, sustainable practices, indigenous cultures','completed','2025-08-25T00:07:34.562Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Community gardening and sustainable practices"}',NULL,NULL,NULL);
