INSERT INTO businesses VALUES('266adcf4-ca81-45b2-98c7-34ee4e508fa0','Mediterra Bakehouse Southwest','226 S Main St, Coolidge, AZ 85128',32.97617879999999957,-111.5182315999999929,'(520) 723-1853','https://www.mediterrabakehouse.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','bakery','Mediterra Bakehouse Southwest is an artisan bread bakery located in Coolidge, Arizona. They specialize in creating a variety of breads using four heritage wheat varieties grown locally in Pinal County, Arizona. Their breads are naturally fermented and hand-shaped, offering a diverse product line that includes loaves, rolls, baguettes, and more. They are unique in their approach of controlling the entire process from seed to crumb, ensuring the highest quality of their products. They also offer preorders with local pickup and have a cafe where customers can enjoy their freshly baked goods.','["artisan breads","white hamburger buns","ciabatinni rolls","seeded rye deli loaf","sourdough deli loaf"]','artisan bread, locally grown wheat, natural fermentation, hand-shaped bread, preorder, local pickup, cafe','completed','2025-08-25T00:24:45.086Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"artisan breads made from locally grown wheat"}',NULL,NULL,NULL);
