INSERT INTO businesses VALUES('0f97cf48-f609-4a10-b8cc-67525e3e94c5','Mochidot Donuts','914 E. Camelback Rd, Phoenix, AZ 85014',33.5095799999999997,-112.0613668999999959,'602-111-1111','mochidot.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','bakery','Mochidot Donuts is a unique bakery business located in central Phoenix, Arizona. It is a family-owned business that specializes in serving fresh small batch mochi donuts with a monthly rotating flavor menu. The business prides itself in offering unique and elevated sweet treats. They offer both online ordering and in-store purchases, with a minimum order of 1 dozen for online orders. They also offer catering services. Their unique approach to traditional donuts, combining them with mochi, sets them apart in the food and dining industry.','["Mochi Donuts","Online Orders","Catering"]','mochi donuts, Asian bakery, Phoenix, family-owned, small batch, rotating flavor menu, online orders, catering','completed','2025-08-24T10:35:41.932Z','firecrawl','{"locally_owned":true,"specialty_focus":"Mochi Donuts"}',NULL,NULL,NULL);
