INSERT INTO businesses VALUES('0f4ca737-6c54-4610-b0f1-e947fcc9433f','Modern Phoenix','4624 N. 11th Place, Phoenix, AZ 85014',33.50461949999999688,-112.0576362000000045,'(602) 363-6158','www.modernphoenix.net','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','arts_entertainment','recreation','Modern Phoenix is a unique business that serves as a neighborhood network for the city of Phoenix, Arizona. It focuses on the preservation and celebration of the city''s architectural heritage, particularly mid-century modern architecture. The business offers a platform for people to learn about the city''s historic properties and neighborhoods, with a special emphasis on the works of renowned architects. It also provides alerts about preservation actions, volunteer opportunities, and organizes modern home tours. Modern Phoenix distinguishes itself by fostering a community of people interested in the city''s architectural history and advocating for the preservation of iconic structures.','["Information about historic properties","Neighborhood guides","Modern home tours","Preservation action alerts","Volunteer opportunities"]','Phoenix, architecture, historic preservation, neighborhood network, home tours, mid-century modern, community','completed','2025-08-24T10:35:02.176Z','firecrawl','{"locally_owned":true,"specialty_focus":"Preservation and celebration of Phoenix''s architectural heritage"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('2a168df6-76bd-4fba-8053-19c776be32fe','Modern Tortilla','739 E Dunlap Ave, Phoenix, AZ 85020',33.56731930000000119,-112.0636377999999951,'(602) 848-8823','moderntortilla.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','food_truck','Modern Tortilla is a food truck business based in Phoenix, Arizona. They specialize in serving a variety of Mexican food items including street tacos, burritos, and quesadillas. The business prides itself on combining southwest culinary roots with classical training to offer the best street tacos in the Valley. They also provide catering services for weddings and other events. The business is unique in its offering of customizable tacos and a wide variety of appetizers. They also offer dessert options like crème filled churros and fresh horchata.','["Street Tacos","Burritos","Quesadillas","Catering Services","Customizable Tacos"]','Food Truck, Mexican Food, Street Tacos, Catering Services, Phoenix, Arizona, Modern Tortilla, Chef Tom D’Ambrosio','completed','2025-08-25T00:32:12.317Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Southwest culinary roots with classical training"}',NULL,NULL,NULL);
