INSERT INTO businesses VALUES('21b68723-e0f7-4fdd-b063-039c16464c4c','Monsoon Chocolate LLC','3630 E. Ft. Lowell Rd, Tucson, AZ 85716',32.26502440000000149,-110.9229863999999993,'15202439661','https://monsoonchocolate.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','cafe','Monsoon Chocolate LLC is a chocolate cafe located in Tucson, Arizona. They are an award-winning chocolate maker and confectioner, drawing inspiration from local ingredients to craft a variety of chocolate products. They distinguish themselves by using transparently-sourced cacao from all over the world and processing it as minimally as possible to reveal the inherent flavors in the beans. They offer a wide range of chocolate products, including bars, bon bons, confections, desserts, and beverages. They also offer nationwide chocolate delivery.','["chocolate bars","bon bons","confections","desserts","beverages","gift cards","custom orders"]','chocolate, confectioner, cafe, transparently-sourced cacao, local ingredients, award-winning, nationwide delivery','completed','2025-08-25T00:15:12.041Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Crafting a variety of chocolate products using transparently-sourced cacao and local ingredients"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('00392516-26e5-4965-b3a3-e8cab9aa1a2c','Monsoon Market','3508 N 7th St Suite 140,, Phoenix, AZ 85014',33.45148035775274309,-112.0498659219295945,'(602) 612-2046','https://www.monsoonmrkt.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','Monsoon Market is a unique grocery market located in Phoenix, Arizona. They specialize in natural wines and a variety of snacks, but their offerings do not stop there. The market also provides non-alcoholic beverages, exclusive pantry items, vintage homeware, and gifts. Monsoon Market distinguishes itself by supporting indie businesses, women-owned businesses, and the local small business community. They also host events and offer a wine club membership for wine enthusiasts. Their focus on natural and unique products, as well as their community involvement, makes them a distinctive business in the retail and grocery market sector.','["Natural wine","Snacks","Non-alcoholic beverages","Exclusive pantry items","Vintage homeware","Gifts","Wine club membership","Event hosting"]','natural wine, snacks, gifts, Phoenix, grocery market, indie business, women-owned business, local small business, wine club, events','completed','2025-08-24T10:02:08.658Z','firecrawl','{"locally_owned":true,"specialty_focus":"Natural wine and unique grocery items"}',NULL,NULL,NULL);
