INSERT INTO businesses VALUES('0a45d865-5876-4d68-a422-b2a149636003','MotoSonora Brewery','1015 S Park Ave, Tucson, AZ 85719',32.20921690000000126,-110.9561108000000047,'520-416-6686','https://motosonora.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','brewery_winery','MotoSonora Brewery is a craft beer brewery located in Tucson, Arizona. Built by a group of dedicated craft beer fans, MotoSonora offers a variety of award-winning beers and provides a space for beer lovers, adventure seekers, locals, and travelers alike. The brewery distinguishes itself by its commitment to creating great beer and providing a comfortable space for customers to relax and share stories. With its diverse range of beers and a welcoming atmosphere, MotoSonora Brewery caters to a wide range of beer enthusiasts.','["Craft Beers","Brewery Tours","Private Events"]','craft beer, brewery, award-winning beers, Tucson, Arizona, MotoSonora, beer tasting, local brewery','completed','2025-08-24T10:26:02.966Z','firecrawl','{"locally_owned":true,"specialty_focus":"craft beer brewing and tasting"}',NULL,NULL,NULL);
