INSERT INTO businesses VALUES('0fafd2bb-c548-48cd-a633-ed2050ed65fc','Mountainside Coffee','327 Main Street, Superior, AZ 85173',33.28699569999999853,-111.1132130000000017,NULL,'https://www.mountainsidecoffee.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','cafe','Mountainside Coffee is a premium coffee and tea business located in Superior, Arizona. They specialize in providing a variety of whole roasted coffee beans, fresh ground coffees, and single-cup coffees and teas from around the world. They are committed to environmental responsibility, offering 100% recyclable single-cup packs. Mountainside Coffee is a division of Tulpehocken Mountain Spring Water, indicating a focus on quality and natural ingredients. They serve coffee and tea enthusiasts who appreciate exotic imports, flavored varieties, and premium favorites.','["whole roasted coffee beans","fresh ground coffees","single-cup coffees","single-cup teas","compatible with Keurig"]','premium coffee, tea, exotic imports, flavored coffee, recyclable single-cup packs, environmental responsibility, Tulpehocken Mountain Spring Water','completed','2025-08-24T10:36:03.796Z','firecrawl','{"locally_owned":true,"specialty_focus":"Premium coffee and tea with a commitment to environmental responsibility"}',NULL,NULL,NULL);
