INSERT INTO businesses VALUES('0422bbec-9dc9-4cd9-ac60-9575ddc9e86d','Move Over Bob','11631 N 134th Way, Scottsdale, AZ 85259',33.48947659562519163,-111.9462633467460648,'480-882-8000','www.moveoverbob.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','education_training','professional_development','Move Over Bob is a media and lifestyle brand that aims to bring tradeswomen to the center of culture, while also growing the pipeline for the next generation. They are unique in their approach as they introduce teen girls to construction through a lifestyle lens, aiming to bridge the skilled trades gap. They offer a magazine that provides a big sister approach to making construction more accessible and aspirational. They also provide resources and a community of women within arm’s reach for support.','["MOB Magazine","Digital Zine","Merchandise","Career Pathways"]','tradeswomen, construction, media, lifestyle, magazine, professional development, career pathways','completed','2025-08-24T10:10:59.585Z','firecrawl','{"locally_owned":true,"specialty_focus":"Promoting women in trades and construction"}',NULL,NULL,NULL);
