INSERT INTO businesses VALUES('02163d18-fb91-4e58-accf-c354947c6432','Mustache Pretzels','9393 N 90th St #102-601, Scottsdale, AZ 85258',33.44497464427158206,-111.967468724264549,'480-744-0372','www.mustachepretzels.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','food_truck','Mustache Pretzels is a unique food truck business based in Scottsdale, Arizona. They specialize in serving hand-rolled and scratch-baked pretzels, shaped like mustaches, made from locally grown, non-GMO flour. Their pretzels come in a variety of flavors including Original Butter, Cinnamon Sugar, and Garlic Parmesan. They also offer vegan options upon request. Their unique pretzel shapes and flavors, combined with their mobile food truck operation, make them a popular and distinctive choice for pretzel lovers across Arizona.','["Original Butter Pretzel","Cinnamon Sugar Pretzel","Garlic Parmesan Pretzel","Vegan Pretzels"]','food truck, pretzels, Arizona, locally grown, non-GMO, vegan options, unique shapes','completed','2025-08-24T10:06:13.986Z','firecrawl','{"locally_owned":true,"specialty_focus":"mustache shaped pretzels"}',NULL,NULL,NULL);
