INSERT INTO businesses VALUES('17c0cd50-c67f-4f60-9ca3-d35b4c9e6c9f','Nalwoodi Denzhone Community','PO Box 758, Globe, AZ 85502',33.46877494047432578,-112.0733451268077232,'928-487-0812','https://apachendc.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','nonprofit_org','Nalwoodi Denzhone Community is a nonprofit organization based in Arizona, dedicated to cultivating a community that enables personal holistic transformation. They serve the San Carlos Apache Reservation community by providing education, outreach, and food distribution services. They distinguish themselves by growing nutritiously dense and culturally significant foods, raising healthy poultry, and distributing monthly food boxes in collaboration with local partners. They also invest in the youth and build leaders who will transform their community.','["Market Garden","Poultry & Egg Production","Food Distribution","Education & Outreach"]','nonprofit, food distribution, education, outreach, community transformation, San Carlos Apache Reservation, holistic','completed','2025-08-24T10:52:05.022Z','firecrawl','{"locally_owned":true,"specialty_focus":"Community transformation and food security"}',NULL,NULL,NULL);
