INSERT INTO businesses VALUES('0dccae76-8705-4a3f-ab0b-15bb03d56abe','National Speakers Association (NSA)','1500 S Priest Dr, Tempe, AZ 85281',33.41197739999999783,-111.9612762000000003,'(480) 968-2552','https://www.nsaspeaker.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','education_training','professional_development','The National Speakers Association (NSA) is a professional development organization that serves professional speakers. They offer a variety of resources and services aimed at helping speakers improve their craft and grow their businesses. The NSA distinguishes itself by providing a community for speakers to share strategies, insights, and experiences. They also offer online courses, events, and a network of marketing experts to help speakers reach and engage their target audiences. Additionally, they provide resources for determining appropriate speaking fees and creating immersive in-person and virtual experiences for audiences.','["Professional development resources","Online courses","Events","Marketing resources","Fee guidance","Experience creation resources"]','professional development, speakers, online courses, events, marketing experts, speaking fees, virtual experiences','completed','2025-08-24T10:32:29.447Z','firecrawl','{"locally_owned":false,"specialty_focus":"Professional speakers"}',NULL,NULL,NULL);
