INSERT INTO businesses VALUES('252ec2d0-bc8b-47a6-8c08-fa0ae8479c4c','Native Nations','3298 North Glassford Hill Road, Suite 104-175, Prescott Valley, AZ 86314',33.4457331313417825,-112.0894547688337183,'623-377-4270','Na7iveNa7ions.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','nonprofit_org','Native Nations is a nonprofit organization dedicated to fostering the growth and development of Native American athletes through baseball. The organization offers a range of programs from grassroots initiatives to elite competition, providing the tools and support athletes need to succeed both on and off the field. Native Nations is committed to creating pathways for players to compete at every level, while staying rooted in their cultural identity as Native athletes. The organization also focuses on nutrition, wellness, and mental health for athletes and their families through their Home Plates program.','["Baseball training and competition","Youth development programs","Health and wellness education","Tribal Tracker player profile","Home Plates nutrition program"]','Native American athletes, baseball, nonprofit, youth development, cultural pride, community values, athlete support, health education','completed','2025-08-25T00:21:32.263Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Native American athlete development"}',NULL,NULL,NULL);
