INSERT INTO businesses VALUES('1cf78b56-12e0-4c72-a468-d4b26fe82f69','Naturoli Beautiful','9299 W. Olive Ave, Peoria, AZ 85345',33.56527460000000218,-112.258367800000002,'623-266-7642','www.naturoli.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','NaturOli Beautiful is a retail business specializing in all-natural personal care and cleaning products. They serve customers who are seeking organic, healthy, and non-toxic alternatives to conventional products. The business distinguishes itself by developing an exclusive line of products based on a proprietary saponin extract from Certified Organic soap nuts. Their offerings include a wide range of products from face cleansers to foot care products to 100% natural laundry detergents, all aimed at nourishing the body and home with eco-friendly collections.','["Soap Nut Products","Household Cleaners","Laundry Extras","Hair Care Products","Face Cleansers","Foot Care Products","Natural Laundry Detergents"]','natural personal care, organic cleaning products, soap nuts, saponin extract, chemical-free, eco-friendly, home cleaning, personal care','completed','2025-08-24T11:02:13.681Z','firecrawl','{"locally_owned":true,"specialty_focus":"Natural personal care and cleaning products"}',NULL,NULL,NULL);
