INSERT INTO businesses VALUES('0095d02b-6229-44ac-8400-10edde5163c6','Nico Barberan - IN Studios','1201 E Lee Street Unit 12, Tucson, AZ 85719',32.21030829236090654,-110.9380867549082979,'224-424-9549','www.nicobarberan.com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','arts_entertainment','music_venue','Nico Barberan - IN Studios is a unique music venue offering a blend of blues, rock, and Latin American popular music. Located in Tucson, Arizona, the business is owned by Nico Barberan, a versatile performer and musician who has journeyed from Chile to the USA. His music is a captivating blend of diverse influences, enriched by his travels across Latin America, Europe, and the United States. Nico also offers music lessons, making his studio a hub for music lovers and learners alike. His music has been recognized for its raw emotion and cultural richness, making each performance a journey around the world.','["Music performances","Music lessons"]','music, blues, rock, Latin American music, music lessons, Nico Barberan, IN Studios, Arizona, performer, musician','completed','2025-08-24T10:02:46.539Z','firecrawl','{"locally_owned":true,"specialty_focus":"Blending blues, rock, and Latin American popular music"}',NULL,NULL,NULL);
