INSERT INTO businesses VALUES('1ccaae6e-4364-411d-a5fb-58c57bb4dc7f','Oak Creek Apple Company','2370 W State Route 89A, Sedona, AZ 86336',33.49754810347918976,-112.0425994123822023,'(928) 298-4040','https://www.oakcreekapplecompany.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','grocery_market','Oak Creek Apple Company is a women-owned small business based in Sedona, Arizona. They specialize in the production and sale of apple cider vinegar with the ''Mother'', magnesium lotion, and other wellness products. They aim to provide solutions for gut health, inflammation, IBS, anxiety, and weight loss. The company also offers educational retreats and classes backed by science. Their unique approach to health and wellness, combined with their commitment to community involvement and sustainable practices, sets them apart in their industry.','["Apple Cider Vinegar With the ''Mother''","Magnesium Lotion","Pain Relief","Gut Health Solutions","Inflammation Solutions","IBS Solutions","Anxiety Solutions","Weight Loss Solutions","Retreats & Classes"]','Apple Cider Vinegar, Magnesium Lotion, Gut Health, Inflammation, IBS, Anxiety Solutions, Weight Loss, Retreats, Classes, Women-owned','completed','2025-08-24T11:01:40.453Z','firecrawl','{"locally_owned":true,"specialty_focus":"Apple Cider Vinegar and Wellness Products"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('00051210-e1cd-4712-9346-da28d15bd0c9','Oak Creek Brewing Company','2050 Yavapai Dr., Sedona, AZ 86336',34.86636839999999893,-111.7961303999999956,'(928) 204-1300','https://oakcreekbrew.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','brewery_winery','Oak Creek Brewing Company is a microbrewery located in Sedona, Arizona. Since 1995, they have been crafting exceptional beer and have become a staple in local grocery stores like Whole Foods and Safeway. They offer a welcoming outdoor beer garden with live music every Friday, Saturday, and Sunday. They also have a kitchen that offers a delicious menu to pair perfectly with their brews. They host live music every weekend and have a karaoke night every Tuesday. They also offer daily happy hour from 4 to 7 PM.','["Craft beers","Live music","Food menu","Happy hour","Karaoke"]','microbrewery, live music, outdoor beer garden, happy hour, karaoke, Sedona, Arizona, craft beer, local brews','completed','2025-08-24T10:01:50.696Z','firecrawl','{"locally_owned":true,"specialty_focus":"Crafting authentic brews since 1995"}',NULL,NULL,NULL);
