INSERT INTO businesses VALUES('2d0663dd-cfa5-4682-9145-53bc2dac1dbf','Page Springs Cellars','1500 N. Page Springs Road, Cornville, AZ 86325',33.44289632105469678,-112.0860276182474422,'(928) 639-3004','pagespringscellars.com/','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','food_dining','brewery_winery','Page Springs Cellars is a winery located in Cornville, Arizona. They offer a variety of wines, including white, rosé, red, and specialty dessert wines. They also have a tasting room and bistro for visitors to enjoy their products. In addition to their wine offerings, they also host events and have a wine club for members. They distinguish themselves by their commitment to supporting local wildlife, as evidenced by their partnership with the Farmland Flyways Trail through Wild Farm Alliance.','["Wine tasting","Wine club membership","Event hosting","Bistro dining"]','winery, wine tasting, wine club, bistro, Arizona wines, wildlife conservation','completed','2025-08-25T00:39:36.180Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Wine production and tasting"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('108fd112-6449-4c59-bddb-a84d2f186e23','Paige Artists Studio Gallery','2136 n. 88th Street, Mesa, AZ 85207',33.45421970000000301,-111.6413347999999957,'(214) 207-9277','susanpaige.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','health_wellness','alternative_medicine','Paige Artists Studio Gallery, run by Susan Paige, OMC, LMT, is an alternative medicine business with a variety of offerings serving people seeking holistic and spiritual healing. With over 40 years of experience, Susan offers a range of workshops, classes, and sessions in Reiki Healing, Intuitive Sessions, Essential Oils, Aromatherapy, and more. She also provides personal and spiritual growth workshops and energy awareness workshops. Additionally, Susan is an ordained minister and offers services for marriage, unions, and other life ceremonies. The business distinguishes itself by offering a wide range of holistic healing services, personal growth workshops, and life ceremonies.','["Reiki Healing","Intuitive Sessions","Essential Oils","Aromatherapy Classes","Personal/Spiritual Growth Workshops","Energy Awareness Workshop","Marriage, Unions, and Life Ceremonies"]','Reiki Healing, Intuitive Sessions, Essential Oils, Aromatherapy, Personal/Spiritual Growth Workshops, Energy Awareness Workshop, Marriage Ceremonies, Life Ceremonies','completed','2025-08-25T00:03:32.569Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Holistic Healing and Personal/Spiritual Growth"}',NULL,NULL,NULL);
