INSERT INTO businesses VALUES('214bdb10-b6ca-4546-b079-73d3b4a569a7','Phoenix Ida','251 West Washington Street, 9th Floor,, Phoenix, AZ 85003',33.48172255551104115,-112.1231843188051584,'602-534-0180','www.phoenixida.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','nonprofit_community','nonprofit_org','Phoenix IDA is a nonprofit organization based in Arizona that is committed to providing access to funding to benefit underserved communities. The organization distinguishes itself by focusing on public finance, community investment, homebuyer assistance, and special projects. They have been actively involved in issuing private activity bonds, awarding grants to Maricopa County nonprofits, assisting new homeowners with down payment assistance, and providing higher education scholarships. Their vision is to be the premiere nonprofit community investor, known for providing the most innovative, efficient, and highest quality services, improving the lives of all Arizonans.','["Public finance","Community investment","Homebuyer assistance","Special projects","Scholarships"]','nonprofit organization, community investment, homebuyer assistance, public finance, Phoenix, Arizona, underserved communities, scholarships, private activity bonds','completed','2025-08-25T00:13:55.183Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Funding for underserved communities"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('238fe1cf-89e8-4c42-b2c3-bda1ac9e84aa','Phoenix Jazzercise','12228 N Cave Creek Rd. Suite 101, Phoenix, AZ 85022',33.41724357814668168,-112.1054537392315069,'(602) 992-1552','https://www.jazzercise.com/location/phoenix-jazzercise-center','other',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','health_wellness','fitness_gym','Phoenix Jazzercise is a fitness gym that specializes in dance fitness classes. Serving the Phoenix, Arizona area, they cater to individuals who are looking for a fun and engaging way to stay fit and healthy. They distinguish themselves by offering Jazzercise, a pulse-pounding, beat-pumping fitness program that gets you results fast. It’s a calorie-torching, hip-swiveling dance party workout to put your abs to the test, with a hot playlist to distract you from the burn.','["Dance fitness classes"]','Phoenix, Jazzercise, dance fitness, fitness center, fitness classes','completed','2025-08-25T00:18:47.681Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Jazzercise dance fitness classes"}',NULL,NULL,NULL);
