INSERT INTO businesses VALUES('0f1820a2-e99e-4ef8-af63-fcf141a876a5','Power Grill Brush','5424 N 73rd Drive, Glendale, AZ 85303',33.51522099999999682,-112.2173738000000042,'623-826-3369','powergrillbrush.com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:32','2025-08-11 18:48:32','retail_shopping','electronics','Power Grill Brush is a retail business specializing in innovative grill cleaning tools. Their products are designed to attach to any power drill, featuring stiff nylon bristles that effectively remove baked-on grime and grease. The company emphasizes safety, offering a safer alternative to traditional wire grill brushes. Their brushes are versatile, with five different sizes and shapes for thorough cleaning of every grill nook and cranny. Power Grill Brush serves customers who value convenience, safety, and effectiveness in grill cleaning.','["Power Grill Brush","Versatile Brush Set"]','grill cleaning, power drill, nylon bristles, safety, convenience, innovative brush set','completed','2025-08-24T10:34:36.866Z','firecrawl','{"locally_owned":true,"specialty_focus":"Innovative grill cleaning tools"}',NULL,NULL,NULL);
