INSERT INTO businesses VALUES('2f80c2be-ef89-4373-b810-265aac0aac3d','Rainbow Pest Control','4333 North 6th Drive, Phoenix, AZ 85013',33.49908409999999748,-112.0822481999999952,'602-451-9812','rainbowpestaz.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','home_services','cleaning_maintenance','Rainbow Pest Control is a pest control service based in Phoenix, Arizona. They offer a variety of pest control services, focusing on the needs of their clients and their community. They are unique in their commitment to supporting the LGBTQ+ community, donating a portion of their profits to LGBTQIA+ causes. Their services include pest control for ants, scorpions, and rodents both inside and outside the home. They also offer a seal out service to prevent future infestations. They pride themselves on their customer service, offering free re-services if a customer is not satisfied.','["Ant control","Scorpion control","Rodent control","Seal out service"]','pest control, LGBTQ+ support, ant control, scorpion control, rodent control, seal out service, customer satisfaction','completed','2025-08-25T00:44:03.851Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Supporting the LGBTQ+ community"}',NULL,NULL,NULL);
