INSERT INTO businesses VALUES('07b0b5ac-5313-48c9-afd8-84c07a862ad7','Revolu Modern Taqueria + Bar','5538 N 7th St, Phoenix, AZ 85014',33.51728260000000148,-112.0650937000000055,'(480) 707-1922 (work)','https://revolutaqueria.com','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','restaurant','Revolu Modern Taqueria + Bar is a modern-day taqueria and bar located in Phoenix, AZ. Inspired by the street food of Tijuana, Mexico, they offer a variety of delicious Mexican dishes and drinks. They serve customers looking for a casual dining experience, as well as those looking for catering services for their special events. They distinguish themselves by their unique Mexican street fare and their commitment to creating memorable experiences for their customers. They also offer online ordering and reservations, catering services, and job opportunities.','["Mexican Dishes","Drinks","Catering Services","Online Ordering","Reservations"]','Modern Taqueria, Bar, Mexican Street Fare, Catering, Online Ordering, Reservations, Job Opportunities','completed','2025-08-24T10:19:46.623Z','firecrawl','{"locally_owned":true,"specialty_focus":"Mexican Street Fare"}',NULL,NULL,NULL);
