INSERT INTO businesses VALUES('1e22f031-ea76-4d9d-aa19-3635c58c0324','Rocking L3 Ranch','6095 E Leisure Ln, Flagstaff, AZ 86004',35.19221744921901518,-111.6115399911161745,'(928) 814-3544','RockingL3Ranch.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','grocery_market','Rocking L3 Ranch is a family-owned farm and ranch located in Northern Arizona. With a heritage dating back to the 1920s, the ranch is committed to sustainable farming practices and provides customers with fresh, high-quality produce and meat products. The ranch grows locally sourced pumpkins and corn and raises Navajo-Churro Lamb. They are dedicated to building stronger and healthier communities by supporting local agriculture. Their team is made up of passionate farmers and ranchers who ensure the well-being of their animals and the health of their crops.','["Locally grown pumpkins","Corn","Navajo-Churro Lamb"]','sustainable farming, locally sourced, Navajo-Churro Lamb, fresh produce, meat products, local agriculture','completed','2025-08-24T23:58:17.064Z','firecrawl','{"locally_owned":true,"specialty_focus":"Sustainable farming and ranching"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('17dccb50-cbf2-4d49-8d14-730fce207c84','Rocky Mountain Painting','537 W Mariposa St, Phoenix, AZ 85013',33.50819899999999763,-112.0812365000000028,'(602) 621-9829','https://greatpainteraz.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','home_services','construction_contractor','Rocky Mountain Painting is a professional painting service based in Phoenix, Arizona. They specialize in both residential and commercial painting services, serving a wide range of areas including Scottsdale, Paradise Valley, Carefree, North Phoenix, Tempe, Mesa, Glendale, Peoria, Goodyear, Avondale, Gilbert, and Casa Grande. They offer a variety of services including interior and exterior renovations, commercial renovations, color consulting, repair, new look, and HOA approved services. They are known for their meticulous attention to detail, high-quality work, and excellent customer service. They use the best paint products available in the market, always considering their customers'' budget.','["Interior Renovations","Exterior Renovations","Commercial Renovations","Color Consulting","Repair","New Look","HOA Approved Services"]','residential painting, commercial painting, interior renovations, exterior renovations, color consulting, repair, new look, HOA approved, Arizona','completed','2025-08-24T10:52:15.099Z','firecrawl','{"locally_owned":true,"specialty_focus":"Residential and commercial painting services"}',NULL,NULL,NULL);
