INSERT INTO businesses VALUES('1d73dbd2-f940-4dd9-8ebd-96f658a0eca5','Rosevest Financial','7220 N. 16th St. Ste. C, Phoenix, AZ 85020',33.4632017937795041,-112.0826348399787946,'(480) 951-5300','rosevestfinancial.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','professional_services','financial_services','Rosevest Financial is a comprehensive financial services firm based in Phoenix, Arizona. They serve a wide range of clients, from young professionals looking to grow their wealth to retirees aiming to protect their legacy. They distinguish themselves by offering a range of services tailored to the unique needs of their clients. Their approach involves not just providing financial advice, but also coaching clients through important life decisions and helping them stay on track with their financial goals.','["Financial Planning","Investment Management","Retirement Planning","Tax Planning","Estate Planning","Exit Planning for Business Owners","Private Client Services"]','Financial Planning, Retirement Planning, Investment Management, Tax Planning, Estate Planning, Exit Planning for Business Owners, Private Client','completed','2025-08-24T23:56:37.091Z','firecrawl','{"locally_owned":true,"specialty_focus":"Comprehensive financial planning and wealth management"}',NULL,NULL,NULL);
