INSERT INTO businesses VALUES('1a4ea7c7-baac-4db8-8ceb-9a2592357f34','Samurai Comics Superstore','1602 E. Indian School Rd., Phoenix, AZ 85016',33.49480510000000066,-112.0474327000000016,'(602) 265-8886','www.samuraicomics.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','books_media','Samurai Comics Superstore is a comic book specialty store serving comic book enthusiasts and collectors in Arizona. Established in 2002, it has grown to be the largest chain of comic book specialty stores in Arizona with four locations in Phoenix, Glendale, Chandler, and Mesa. They distinguish themselves by offering a wide range of comic books, graphic novels, manga, anime, toys, collectibles, and gaming supplies. They also host live sales every Tuesday night and offer appraisal services for those looking to sell their comic books or collections.','["Comic books","Graphic novels","Manga","Anime","Toys","Collectibles","Gaming supplies","Live sales","Comic book appraisal"]','comic books, graphic novels, manga, anime, toys, collectibles, gaming supplies, live sales, appraisal services','completed','2025-08-24T10:56:28.386Z','firecrawl','{"locally_owned":true,"specialty_focus":"Comic book specialty store"}',NULL,NULL,NULL);
