INSERT INTO businesses VALUES('11134ba1-e557-4156-9a84-2080710a519c','SanTan Brewing Company','8 S. San Marcos Place, Chandler, AZ 85225',33.30322660000000212,-111.8423104000000023,'480-917-8700','https://santanbrewing.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','brewery_winery','SanTan Brewing Company is a leading craft beer brewery based in Arizona. They serve a wide array of customers, from local beer enthusiasts to tourists seeking a unique Arizona brewery experience. What sets them apart is their commitment to innovation and sustainability, with a brewing process that conserves water and reduces greenhouse gas emissions. They also have a grain-to-farm program, where spent grain is given back to local farmers. In addition to their award-winning beers, they offer spirits, ready-to-drink cocktails, and low-calorie options.','["Craft Beer","Spirits","Ready-to-drink cocktails","Distillery Tours","Catering Services","Merchandise"]','craft beer, sustainability, innovation, Arizona brewery, spirits, ready-to-drink cocktails, low-calorie options','completed','2025-08-24T10:39:04.193Z','firecrawl','{"locally_owned":true,"specialty_focus":"Sustainable brewing process and innovative beer offerings"}',NULL,NULL,NULL);
