INSERT INTO businesses VALUES('243a2c5d-dc83-4c07-8328-5def3e145f2a','Scratching the Plate','109 E. Grant Rd, Tucson, AZ 85705',32.25040200000000112,-110.9707338999999991,'520-820-4515','Www.scratchingtheplate.com.','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','catering','Scratching the Plate is a catering business based in Tucson, Arizona, specializing in meals made from scratch using traditional cooking methods. Run by Chef Pablo Valencia, the business is committed to sustainable local sourcing and aims to create conversations around the table again. They cater to private events, corporate events, and offer meal preps and a private chef experience. Their unique approach to cooking, using wood fire, brings back the appreciation for what food was in the past. They strive to return to the table, return to how food was, and return to all the memories made around the plate.','["catering for private events","catering for corporate events","meal preps","private chef experience"]','catering, meal prep, private chef, sustainable local sourcing, wood fire cooking, Scratching the Plate, Chef Pablo Valencia','completed','2025-08-25T00:19:46.159Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"sustainable local sourcing and traditional cooking methods"}',NULL,NULL,NULL);
