INSERT INTO businesses VALUES('0cc8ed84-ae3c-4f34-9b83-7890914720a8','Sears Coaching','5310 S Palm Dr, Tempe, AZ 85283',33.37560390000000154,-111.9293894000000051,'520-331-2156','www.searscoaching.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','education_training','tutoring_training','Sears Coaching is a professional coaching service based in Tempe, Arizona. They serve individuals and businesses with a variety of coaching needs. Their unique approach to coaching distinguishes them in the field. The specific services they offer are not listed on the website, but coaching services typically include personal development, career guidance, and business strategy.','["personal coaching","career coaching","business coaching"]','coaching, professional development, career guidance, business strategy','completed','2025-08-24T23:53:03.219Z','firecrawl','{"locally_owned":true,"specialty_focus":"professional coaching"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('1556fad0-4750-46ab-9324-71e564f7fbe5','Secure Lane','3220 S DODGE BLVD STE 8, Tucson, AZ 85713',32.25301693984452811,-111.0116145858983288,'(520)780-9751','www.secure-lane.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','manufacturing_industrial','equipment_machinery','Secure Lane is a Tucson, Arizona-based business specializing in traffic control and vehicle access control products. Serving contractors, business owners, architects, engineers, security managers, home owner associations, and parking lot managers, Secure Lane offers a wide range of products including barrier gates, traffic spikes, speed bumps, and vehicle detection loops. The company prides itself on providing solutions to vehicle and traffic access control needs, offering discounts and excellent customer service. Secure Lane is also an authorized and certified distributor of various brands in the field.','["Barrier Gate Operators","Traffic Control Spikes","Vehicle Access Control Products","Magnetic Auto Control Barrier Gate Operators","Door King Barrier Gates","Door King Automated Spikes","RoadBlade Directional Tire Spikes","Guardian Traffic Spike Systems","Speed Bumps","Vehicle Detection Loops"]','traffic control, vehicle access control, barrier gates, traffic spikes, speed bumps, vehicle detection loops, Magnetic Auto Control Barrier Gate Operators, Door King Barrier Gates, Door King Automated Spikes, RoadBlade Directional Tire Spikes, Guardian Traffic Spike Systems','completed','2025-08-24T10:47:46.512Z','firecrawl','{"locally_owned":true,"specialty_focus":"Traffic control and vehicle access control products"}',NULL,NULL,NULL);
