INSERT INTO businesses VALUES('01022e3f-352d-4c50-a72b-174698b28c1d','Shield Fiduciary Services','6424 E. Greenway Pkwy Suite 550, Scottsdale, AZ 85254',33.49763088785601183,-111.9134997151456333,'(602) 606-7955','ShieldFiduciary.Com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','professional_services','legal_services','Shield Fiduciary Services is a professional legal service provider based in Arizona. They specialize in Trust Administration, Estate Management, Conservatorships, and Guardianships. Their services are highly individualized, ensuring dignity and respect are at the core of their operations. They are committed to removing the anxiety from dealing with difficult and stressful situations, keeping clients informed during the process. The firm''s principal is a licensed attorney with specialization in preparation of wills, trusts, and elder law. Their team also includes a retired Assistant District Attorney, a PhD in Psychology, and two psychology graduates.','["Trust Administration","Estate Management","Conservatorships","Guardianships"]','Trust Administration, Estate Management, Conservatorships, Guardianships, fiduciary services, Arizona legal services, elder law','completed','2025-08-24T10:03:44.111Z','firecrawl','{"locally_owned":true,"specialty_focus":"Fiduciary services"}',NULL,NULL,NULL);
