INSERT INTO businesses VALUES('0170d5f4-b60a-4bc0-9e76-46373bc7175a','Shirts N Things','1840 West Southern Ave, Mesa, AZ 85202',33.39370300000000213,-111.8710159999999974,'(480) 827-0256','www.shirtsnthingsaz.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','clothing_fashion','Shirts N Things is a retail store based in Mesa, Arizona, specializing in a wide range of clothing and accessories with a focus on band shirts, novelty items, and rock, punk, and metal-themed merchandise. They serve a diverse clientele, particularly those interested in music and alternative fashion. The store distinguishes itself by offering a vast selection of unique items, including band and movie shirts, hoodies, jackets, wallets, bags, shoes, and home decor. They also provide a variety of accessories like patches, pins, rings, and studs. Shirts N Things is a locally owned business, supporting the local community and providing a unique shopping experience for customers.','["Band Shirts","Movie Shirts","Novelty Shirts","Hoodies","Jackets","Wallets","Bags","Shoes","Home Decor","Accessories"]','band shirts, rock fashion, punk fashion, metal fashion, novelty shirts, alternative fashion, unique accessories','completed','2025-08-24T10:05:01.507Z','firecrawl','{"locally_owned":true,"specialty_focus":"Alternative fashion and band merchandise"}',NULL,NULL,NULL);
