INSERT INTO businesses VALUES('33b75a6d-d5f5-48ab-a410-45584a3c8bea','Siphon Draw Apothecary','4650 N Mammoth Mine Rd, Apache Junction, AZ 85119',33.44547558363294116,-112.0306047954954635,'480-528-6247','www.siphondraw.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','beauty_personal_care','skincare_spa','Siphon Draw Apothecary is a skincare and spa business located in the Superstition Mountains of Arizona. They specialize in handcrafting clean skincare products in small batches, using fresh, wild-harvested botanicals gathered from the surrounding desert. Their offerings include a wide range of products such as soaps, bath bombs, body and facial skincare items, and remedies. They are passionate about creating results-driven, non-toxic products using the finest organic, local, and ethically sourced ingredients. They believe in nurturing the skin’s own resiliency and delivering powerful healing benefits.','["Soap","Aromatherapy","Bath Bomb","Body Skincare","Facial Skincare","Honey & Tea Remedies","Gifts"]','organic skincare, handcrafted, wild-harvested botanicals, non-toxic products, Superstition Mountains, Siphon Draw Apothecary','completed','2025-08-25T00:54:40.172Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Organic skincare handcrafted with wild-harvested botanicals"}',NULL,NULL,NULL);
