INSERT INTO businesses VALUES('0a2a1445-0cb2-4d8c-b91b-3011de0f419b','Sisu Consulting','2401 N 66th Street, Scottsdale, AZ 85257',33.47449399999999998,-111.9396430000000037,'3125360574','sisu-consulting.net','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','professional_services','consulting','Sisu Consulting is a professional consulting business based in Scottsdale, Arizona. They specialize in partnering with communities to reimagine cities, systems, and stories. Their work centers around community agency, remapping power structures, and co-designing initiatives. They are committed to liberation, creativity, and radical care, and refuse to give up on community, justice, or the right to dream new systems into being. They connect practice with power, guiding real strategies, policy, and systems change. They root planning in transformative justice, meaningfully weaving healing into processes and outcomes.','["Community consulting","Systems remapping","Co-design initiatives","Strategic planning","Policy change"]','community agency, power structures, co-design initiatives, liberation, creativity, radical care, transformative justice','completed','2025-08-24T10:25:42.561Z','firecrawl','{"locally_owned":true,"specialty_focus":"Community agency and transformative justice"}',NULL,NULL,NULL);
