INSERT INTO businesses VALUES('128047f4-93e6-430c-b20f-a9383f5acdd0','Small Farms Big Minds','921 E. Orange Drive, Phoenix, AZ 85014',33.5118620000000007,-112.0614386000000024,NULL,'https://smallfarmsbigminds.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','education_training','professional_development','Small Farms Big Minds is an Arizona-based organization focused on training the next generation of farming professionals in regenerative agriculture. They serve individuals interested in farming and environmental protection, aiming to end food insecurity and promote sustainable farming practices. Their unique approach involves working with the environment rather than against it, to feed growing communities. They offer opportunities for involvement through volunteering and donations, and they are dedicated to building a community invested in protecting the environment.','["Farming education","Community building initiatives","Volunteering opportunities"]','regenerative agriculture, farming education, environmental protection, food insecurity, community building, volunteering','completed','2025-08-24T10:42:07.343Z','firecrawl','{"locally_owned":true,"specialty_focus":"Regenerative agriculture education"}',NULL,NULL,NULL);
