INSERT INTO businesses VALUES('2454e403-201a-45b4-9b01-b5c02794f388','Smartbox Company','2063 east cedar street, Tempe, AZ 85281',33.41194089999999762,-111.8972741999999983,'480-921-4100','https://thesmartboxcompany.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','manufacturing_industrial','equipment_machinery','Smartbox Company is a modern solution provider for sound and space distractions. They serve businesses in need of professional privacy and focus, especially those on the go. They distinguish themselves by offering customizable design options to match any facility or corporate brand. Their main product, the smartBOX, is designed to provide a quiet and focused space, making it an ideal solution for open offices, coworking spaces, and any environment where noise and distractions can be a challenge.','["smartBOX","workBOX","customizable design options"]','smartBOX, sound solution, space solution, professional privacy, customizable design, quiet space, focused space','completed','2025-08-25T00:20:04.410Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Providing sound and space solutions with customizable design options"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('297d3684-3b65-4565-b30e-04282bafdf1d','Smell N Bomb','59 W 1st Ave, 105, Mesa, AZ 85210',33.43206874224586755,-111.8582550974265217,'405-774-3456','www.smellnbomb.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','beauty_personal_care','skincare_spa','Smell N Bomb is a skincare and spa business specializing in the creation and sale of handmade, vegan, luxury bath bombs and other bath treats. They serve customers who value self-care and wellness, offering a spa-like experience in the comfort of their homes. Smell N Bomb distinguishes itself by using all-natural ingredients with premium essential and fragrance oils in their products, and by offering a unique geode-design aesthetic in their bath bombs. They also offer wholesale products and promote mental wellness.','["Handcrafted Soap","Geode Collection","Shower Steamer Collection","Mental Wellness Products","Wholesale Bath Products"]','vegan bath bombs, handmade bath treats, geode bath bombs, self-care, mental wellness, wholesale bath products','completed','2025-08-25T00:29:34.704Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Handmade, vegan, luxury bath bombs with a unique geode-design aesthetic"}',NULL,NULL,NULL);
