INSERT INTO businesses VALUES('316b4061-c6a3-4543-9d69-bec3e66715d3','Smelter Town Brewery','921 Main Street, Suite A, Clarkdale, AZ 86324',33.43968489213202133,-112.0920464284365182,'(928) 821-0814','https://www.smeltertownbrewery.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','brewery_winery','Smelter Town Brewery is a craft beer brewery located in Clarkdale, Arizona. They specialize in creating finely crafted beers with passion and creativity, representing the local community. The brewery offers a variety of innovative beers, each with a unique flavor profile. They also host a food truck, Sidewalk Grill, serving burgers, sandwiches, and daily specials. The brewery is situated in the same building as the Park Hotel, making it an ideal destination for tourists and locals alike. They also offer dog-friendly patios, making it a welcoming place for pet owners.','["Clark''s Copper Amber Ale","Main Street Blonde Ale","Hop Deposits Hazy IPA","Slag Out Stout","Food from Sidewalk Grill"]','Craft Beer, Brewery, Clarkdale, Arizona, Food Truck, Park Hotel, Dog-Friendly Patios','completed','2025-08-25T00:48:31.667Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Craft Beer Brewing"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('082c61e9-45b2-45d4-b01b-b88f71538852','SMILE Biscotti','717 E Maryland Ave #110, Phoenix, AZ 85014',33.40971472757738781,-112.0459554955632342,'602-758-7292','www.smilebiscotti.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','bakery','SMILE Biscotti is a unique bakery business based in Phoenix, Arizona, that serves freshly prepared biscottis. It distinguishes itself by providing culinary training experiences for young adults on the autism spectrum. The business is a private entrepreneurial venture that is transitioning and expanding to blend with Essential Piece Enterprise, a new sister entity of Arizona Autism Charter Schools. This partnership aims to create more work experiences for adults with autism.','["Freshly prepared biscottis","Culinary training experiences for young adults on the autism spectrum"]','biscotti, autism, culinary training, young adults, work experiences, Arizona Autism Charter Schools, Essential Piece Enterprise','completed','2025-08-24T10:21:36.720Z','firecrawl','{"locally_owned":true,"specialty_focus":"providing work experiences and training for young adults with autism"}',NULL,NULL,NULL);
