INSERT INTO businesses VALUES('1cee2618-7f7b-49b9-b9f9-8e29cd23e09e','Sonoita Vineyards','290 Elgin-Canelo Road, Elgin, AZ 85611',31.6234484000000009,-110.5483085999999986,'520-455-5893','www.sonoitavineyards.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','brewery_winery','Sonoita Vineyards is a winery and vineyard located in Elgin, Arizona. As the oldest commercial vineyard and winery in the state, it serves wine enthusiasts and tourists with a variety of offerings. The vineyard distinguishes itself by its unique location at an elevation of 5,000 feet, surrounded by mountain ranges, which contributes to the unique taste of its wines. They offer wine tastings, private tours, and host private events including weddings. They also provide camping facilities for Harvest Host members.','["wine tasting","private tours","private events","weddings","gift cards","camping"]','winery, vineyard, wine tasting, private tours, private events, weddings, camping, Harvest Host','completed','2025-08-24T11:02:04.928Z','firecrawl','{"locally_owned":true,"specialty_focus":"oldest commercial vineyard and winery in Arizona"}',NULL,NULL,NULL);
