INSERT INTO businesses VALUES('0c137137-195a-4663-877b-5bc8952f2233','Sonoran Glass School','633 W. 18th Street, Tucson, AZ 85701',32.21145049999999799,-110.9783089999999959,'520-302-7449','sonoranglass.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','education_training','workshops_seminars','Sonoran Glass School is a non-profit educational organization based in Tucson, Arizona, dedicated to the art of glassmaking. They offer a variety of courses, workshops, and one-on-one experiences to teach students and the general public about creating and appreciating glass as a visual arts medium. They also host visiting artist seminars and community events funded by members and supporters. The school is equipped with a Hot Shop, Flame Shop, Warm Shop, and Cold Shop, each offering public classes, rentable studio hours for glass artists, and other programming. They also offer a youth education program and creative aging mobile glassblowing.','["Glassblowing classes","Glass Fusing classes","Torch Working classes","Cold Working classes","Youth Education Program","Creative Aging Mobile Glassblowing"]','glass art, educational organization, glassblowing, workshops, seminars, community events, youth education, creative aging','completed','2025-08-24T10:28:52.805Z','firecrawl','{"locally_owned":true,"specialty_focus":"glass art education"}',NULL,NULL,NULL);
