INSERT INTO businesses VALUES('0fa88205-84db-486b-965a-1d5470b70099','Sonsons Pasty Co','1430 W Warner Rd, Gilbert, AZ 85233',33.33629729999999825,-111.8215569999999986,'602-300-0344','sonsonspastyco.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','restaurant','Sonsons Pasty Company is a restaurant business located in Gilbert, Arizona, specializing in the creation and sale of traditional Cornish pasties. Inspired by family traditions and a passion for authentic, handcrafted pasties, the company offers a variety of pasty flavors, including steak and sausage, chicken, and plant-based options. The business is rooted in the heart of Cornwall, England, and prides itself on using traditional recipes and the finest ingredients to offer an unforgettable taste experience. They serve people who crave a taste of Cornwall, whether they prefer meat or vegetarian options.','["Traditional Steak Pasty","Ground Beef Pasty","Steak + Cheese Pasty","Philly Cheese Steak Pasty","Cornish Cheezy Pasty","Chicken Green Chili Pasty","Cottage Pie Pasty","Chicken Pot Pie Pasty","Cheese + Onion Pasty","Pork Pie Pasty","Small Pot Pies","Sausage Rolls","Cherry Pie","Apple Pie"]','Cornish pasties, handcrafted pasties, traditional recipes, steak and sausage pasty, chicken pasty, plant-based pasty, Gilbert, Arizona','completed','2025-08-24T10:35:52.694Z','firecrawl','{"locally_owned":true,"specialty_focus":"Traditional Cornish pasties"}',NULL,NULL,NULL);
