INSERT INTO businesses VALUES('02de972a-1886-4ed4-8285-b392056b891d','Source','3150 E Ray Rd #104, Gilbert, AZ 85296',33.35776498854305316,-111.8132564740258345,'(480) 687-7732','https://eatatsource.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','restaurant','Source is a Mediterranean food and wine restaurant located in Gilbert, Arizona. They pride themselves on being an ingredient-driven, community-centered establishment with a counter service restaurant, wine bar, and retail shop. They offer a comfortable dining experience with meticulously selected food and drink. Source supports farmers and artisans who embody their ethos of integrity, quality, and reflection. They also provide catering services and have a rewards program for loyal customers.','["Mediterranean cuisine","wine","catering services","retail shop","rewards program"]','Mediterranean food, wine bar, retail shop, catering, community-centered, ingredient-driven, rewards program','completed','2025-08-24T10:08:27.048Z','firecrawl','{"locally_owned":true,"specialty_focus":"Mediterranean food and wine"}',NULL,NULL,NULL);
