INSERT INTO businesses VALUES('1ace727c-bbd6-491e-8cd3-25dd169043c7','Southern Arizona Arts & Cultural Alliance','4500 N Oracle Rd #110, Tucson, AZ 85705',32.17867975020983807,-110.9534655402611491,'(520) 797-3959','https://www.saaca.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','arts_entertainment','event_venue','The Southern Arizona Arts & Cultural Alliance (SAACA) is a nonprofit organization dedicated to the creation, preservation, and advancement of the Arts. They provide a variety of services and opportunities for artists, including public art and mural administration, cultural asset mapping and consulting, arts and business partnerships, arts advocacy, and arts education. They also organize numerous events such as art and music festivals, culinary events, and live music performances. SAACA is unique in its commitment to fostering a thriving arts community in Southern Arizona through innovative, collaborative programs and events.','["Public Art & Mural Administration","Cultural Asset Mapping & Consulting","Arts & Business Partnerships","Arts Advocacy","Arts Education","Festival & Event Services"]','arts, culture, public art, cultural asset mapping, arts advocacy, arts education, festivals, culinary events, live music, nonprofit','completed','2025-08-24T10:57:39.449Z','firecrawl','{"locally_owned":true,"specialty_focus":"Arts & Culture"}',NULL,NULL,NULL);
