INSERT INTO businesses VALUES('0b4af983-1840-422a-8c47-2527658b1db3','Spicy Sassy Dulces','10253 W Golden Ln, Peoria, AZ 85345',33.56327249999999651,-112.2802073999999948,'727-432-3971','www.spicysassydulces.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','grocery_market','Spicy Sassy Dulces is a unique Arizona-based business specializing in the creation and sale of handcrafted Chamoy and Chamoy Dulces. They are committed to providing high-quality, vegan, gluten-free, and dye-free products. Their offerings are deeply rooted in tradition and made with utmost care. They transform traditional dulces with a spicy twist, using their handcrafted chamoy and unique spicy blend. They also offer a variety of vegan and gluten-free options, catering to a wide range of dietary needs. The business was born out of a personal craving and has since grown, with the founder''s family and work colleagues being the first taste testers.','["Handcrafted Chamoy","Chamoy Dulces","Vegan Dulces","Gluten-free Dulces"]','Handcrafted Chamoy, Chamoy Dulces, Vegan, Gluten-free, Dye-free, Spicy Sweets, Arizona','completed','2025-08-24T10:27:35.744Z','firecrawl','{"locally_owned":true,"specialty_focus":"Handcrafted Chamoy and Chamoy Dulces"}',NULL,NULL,NULL);
