INSERT INTO businesses VALUES('1b43899a-0b50-4f43-a640-d50132abfcb1','Spirit Mountain Roasting Co./The Coffee Shop','400 Picacho Rd. Suite D., Winterhaven, AZ 92283',33.46831132392474473,-112.0501054559821625,'480-329-4248','www.spiritmountainroasting.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','cafe','Spirit Mountain Roasting Co. is a Native American owned cafe business that specializes in offering high-quality coffee sourced from around the world and roasted in small batches. They are committed to sustainability and ethical practices, using earth-friendly materials in their process. They serve coffee enthusiasts who appreciate the taste, experience, and enjoyment of specialty coffee. Their unique selling point is their ''Indigenous from seed to cup'' philosophy, which reflects their commitment to their cultural heritage and to delivering a unique coffee experience to their customers.','["Guatemala - Huehue","Spirit Blend","Colombia - Tolima","Espresso Blend","Ethiopia - Limmu Kossa","Mexico - CESMACH","Chipotle Cold Brew"]','Native American owned, specialty coffee, small batch roasting, sustainable, ethically crafted, indigenous from seed to cup','completed','2025-08-24T10:58:29.259Z','firecrawl','{"locally_owned":true,"specialty_focus":"Indigenous from seed to cup specialty coffee"}',NULL,NULL,NULL);
