INSERT INTO businesses VALUES('0c262c60-3d17-4f08-b281-e3431b477ff7','Stardust Building Supplies','1720 W Broadway Rd,  Suite 101, Mesa, AZ 85202',33.43168988434081257,-111.8300126417279615,'617-803-0890','stardustbuilding.org','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','nonprofit_community','nonprofit_org','Stardust Building Supplies is a nonprofit organization based in Arizona that specializes in providing affordable, reclaimed building supplies to the community. Serving over 3,000 people every month, they are committed to sustainability and waste reduction by repurposing materials that would otherwise end up in landfills. They offer deconstruction services, home pickups, and accept material donations. Additionally, they provide a platform for shoppers and contractors to purchase or donate materials. Their mission is driven by a vision of a world without waste, and they have successfully diverted over 100 million pounds of usable material from the landfill since their inception in 1997.','["Deconstruction Services","Home Pickup","Material Donation","Gifts In Kind","Triple R Certification"]','reclaimed building supplies, deconstruction services, home pickup, material donation, sustainability, waste reduction, nonprofit','completed','2025-08-24T10:29:30.857Z','firecrawl','{"locally_owned":true,"specialty_focus":"Reusing and repurposing building materials to reduce waste and support sustainability"}',NULL,NULL,NULL);
