INSERT INTO businesses VALUES('14e9cf8d-8dde-4b5f-abe4-d6b7f881866d','State Forty Eight','3245 N. Arizona Ave. Suite E4, Chandler, AZ 85225',33.28175711045192032,-111.8739665577020901,'480 226 1745','statefortyeight.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','clothing_fashion','State Forty Eight is a clothing and fashion business based in Chandler, Arizona. They offer a wide variety of clothing items inspired by the state of Arizona, serving individuals of all ages and genders. The business distinguishes itself by providing unique, Arizona-themed designs across a range of products, including men''s and women''s t-shirts, outerwear, youth clothing, and accessories. They also offer a range of specialty items such as drinkware, pins, and stickers. State Forty Eight is a locally owned business that takes pride in its Arizona roots, and this is reflected in their product offerings.','["Men''s t-shirts","Women''s t-shirts","Youth t-shirts","Outerwear","Accessories","Hats","Stickers","Decals","Drinkware","Pins","Leather","Golf Postcards","Necklaces","Magnets","Pets"]','Arizona-themed clothing, men''s t-shirts, women''s t-shirts, youth clothing, accessories, drinkware, pins, stickers','completed','2025-08-24T10:46:26.913Z','firecrawl','{"locally_owned":true,"specialty_focus":"Arizona-themed clothing and accessories"}',NULL,NULL,NULL);
