INSERT INTO businesses VALUES('1bb9dd3c-77b4-4304-b154-b3e028dca3c1','Steadfast Farm','5111 S. Inspirian Parkway, Mesa, AZ 85212',33.32254309999999719,-111.6169845000000009,'(480) 793-1734','www.steadfast-farm.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','grocery_market','Steadfast Farm is a bio-intensive market farm based in Mesa, Arizona. They specialize in growing fruits, vegetables, and flowers using organic practices and raising pastured poultry for eggs throughout the year. Their offerings cater to health-conscious consumers and local businesses looking for fresh, organic produce. They distinguish themselves by their commitment to sustainable farming practices and their wide distribution channels, including their farm store, farmers markets, local stores, and restaurants.','["organic fruits","organic vegetables","pastured eggs","cut flowers","consulting services"]','organic farming, pastured poultry, farm store, farmers markets, local produce, Mesa, Arizona','completed','2025-08-24T10:59:53.930Z','firecrawl','{"locally_owned":true,"specialty_focus":"bio-intensive farming and organic produce"}',NULL,NULL,NULL);
