INSERT INTO businesses VALUES('2f1f0b85-e231-43e6-923f-465e305ad2b1','Stuttering And Speech Therapy Of Arizona','3635 E Inverness Ave Ste 104, Mesa, AZ 85206',33.45729688032216842,-111.8211009660308405,'480-719-6535','www.stutteringtherapyaz.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','health_wellness','medical_services','Stuttering And Speech Therapy Of Arizona is a specialized medical service provider serving individuals with communication difficulties, particularly those who stutter. They distinguish themselves by offering a collaborative approach to therapy, working closely with clients and their families to set goals and track progress. Their services are offered both in-person and virtually, providing a safe and welcoming environment for clients to practice their communication skills. The clinic is owned by a Speech Language Pathologist, emphasizing their commitment to providing professional and effective care.','["Individual Stuttering Therapy","Group Stuttering Therapy","In-Person Therapy","Virtual Therapy"]','stuttering therapy, speech therapy, communication skills, speech-language pathologists, Arizona, individual therapy, group therapy','completed','2025-08-25T00:43:12.401Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Stuttering and Speech Therapy"}',NULL,NULL,NULL);
