INSERT INTO businesses VALUES('103e29ca-c612-4218-90ff-ed0256108deb','Superstition Mountain Lost Dutchman Museum','4087 E Apache Trail, Apache Junction, AZ 85119',33.49017841668054985,-112.1049595881703028,'480-232-3956','www.smldm.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','arts_entertainment','recreation','Superstition Mountain Lost Dutchman Museum is a unique recreational and educational facility located in Apache Junction, Arizona. It serves as a cultural hub for locals and tourists interested in the rich history and mysteries of the Superstition Mountains. The museum distinguishes itself by offering a wide array of exhibits, lectures, and tours. It also houses the Elvis Chapel and a Stamp Mill, adding to its diverse offerings. The museum is currently closed for renovations and will reopen in 2025.','["Exhibits","Events","Grounds Tours","Lectures","Museum Shop","Membership","Rentals"]','museum, Superstition Mountains, history, recreation, Apache Junction, Elvis Chapel, Stamp Mill','completed','2025-08-24T10:37:20.661Z','firecrawl','{"locally_owned":true,"specialty_focus":"Superstition Mountains history and mysteries"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('19f4565b-f27a-4f40-babb-3b0fc8238a8a','Supertree Services','10350 Stardust Tr., Flagstaff, AZ 86004',35.24494054127270459,-111.6468677116055375,'(928) 526-2287','flagstafftreeservices.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','home_services','landscaping_lawn','Supertree Services is a professional tree care business serving homeowners and businesses in Flagstaff and Northern Arizona. With over 28 years of experience, they specialize in tree trimming, pruning, cutting, and removal. They also offer wildfire protection services and tree inspections for bark beetles. The business is locally owned and operated by Larry and Barbara Phillips, with Larry being a certified arborist and experienced wildland firefighter. They are dedicated to maintaining the health of trees and protecting properties from wildfire damage.','["Tree Trimming","Tree Pruning","Tree Cutting & Removal","Wildfire Protection","Tree Inspection"]','tree services, arborist, tree trimming, tree pruning, tree cutting, tree removal, wildfire protection, tree inspection, bark beetles','completed','2025-08-24T10:55:13.379Z','firecrawl','{"locally_owned":true,"specialty_focus":"Certified Arborist, Wildfire Protection"}',NULL,NULL,NULL);
