INSERT INTO businesses VALUES('31a06173-5380-4376-bbe7-5d6674f204b7','Surprise Community Garden','16752 North Greasewood Street, Surprise, AZ 85378',33.63617500000000148,-112.330510799999999,'623-584-4999','https://benevilla.org/community-garden/','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','nonprofit_community','community_center','Surprise Community Garden is a nonprofit community center located in Surprise, Arizona. It provides local residents with a unique opportunity to grow their own fresh fruits, vegetables, and herbs in a supportive and inclusive environment. The garden is designed to foster a strong sense of community, wellness, and sustainability. It offers raised bed rentals for individuals and families, making it an ideal space for both beginners and experienced gardeners. The garden also serves as a hub for educational workshops on sustainable gardening, composting, desert planting, and healthy eating. It encourages volunteerism and community involvement in maintaining shared spaces and assisting fellow gardeners.','["Raised bed rentals","Educational workshops on sustainable gardening and healthy eating","Volunteer opportunities"]','community garden, raised bed rentals, educational workshops, volunteer opportunities, sustainable gardening, composting, desert planting, healthy eating','completed','2025-08-25T00:49:38.987Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Community gardening and education"}',NULL,NULL,NULL);
