INSERT INTO businesses VALUES('2043bb9b-2ab0-4bbf-920c-593fb7168894','Suttle Crossland Wealth Advisors','20715 North Pima Road Suite 108, Scottsdale, AZ 85255',33.5141172081307488,-111.9041841208482282,'602-834-3905','https://www.suttlecrossland.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','professional_services','financial_services','Suttle Crossland Wealth Advisors is a fiduciary investment advisory firm based in Scottsdale, Arizona. They offer a wide range of financial services to individuals and businesses, with a focus on wealth management, financial planning, and estate planning. The firm is unique in its fee-only approach, meaning they are paid directly by their clients and not by investment companies. This ensures that their advice is unbiased and in the best interest of their clients. They also offer services like business valuation, real estate exchange, and retirement planning.','["Financial Planning","Wealth Management","Estate Planning","Trust Services","Business Valuation","Real Estate Exchange","Solo 401k Plans","Small Business 401k Plans"]','Wealth Management, Financial Planning, Estate Planning, Business Valuation, Real Estate Exchange, Retirement Planning, Fee-Only, Fiduciary','completed','2025-08-25T00:10:44.924Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Fee-Only Financial Planning and Wealth Management"}',NULL,NULL,NULL);
