INSERT INTO businesses VALUES('2129546a-0f26-442a-91ee-0b7ce864c9d2','Sweet Country Charm Fudge and Gifts','618 N Beeline Hwy, Payson, AZ 85541',34.24764569999999964,-111.322654700000001,'(928) 978-0640','https://paysonfudge.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','gifts_novelty','Sweet Country Charm Fudge & Gifts is a local business in Payson, Arizona, specializing in homemade sweets and gifts. The business has been crafting homemade fudge since 2009, offering over 180 rotating fudge flavors and a large variety of other sweets. In addition to its sweet offerings, the shop also sells handmade gifts crafted by local artists. The shop has been voted as the Best Gift Shop in Rim Country for four consecutive years, and it also offers a unique product called the Whirzle, a frozen fudge drink with unlimited flavor possibilities.','["Homemade Fudge","Handmade Gifts","Whirzle Frozen Fudge Drink"]','homemade fudge, gift shop, handmade gifts, local artists, Whirzle, frozen fudge drink','completed','2025-08-25T00:13:33.161Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Homemade Fudge and Handmade Gifts"}',NULL,NULL,NULL);
