INSERT INTO businesses VALUES('0541134d-41e6-485b-87fd-049f25ccfed7','Talamante & Associate','6601 W Indian School Rd Ste 30, Phoenix, AZ 85033',33.3990520901686736,-112.0688288804534523,'6028290093','talamanteandassociate.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','professional_services','accounting_tax','Talamante & Associate is a professional tax and accounting service based in Phoenix, Arizona. They offer a comprehensive range of services for both personal and business tax filings, ensuring accuracy and compliance with the latest tax laws. Their goal is to maximize returns and minimize liabilities for their clients. In addition to tax services, they also provide bookkeeping and payroll services, business incorporation guidance, tax audit representation, notary services, and translation and language support. The business is led by Marybell Talamante, a dedicated business leader with extensive experience in financial and tax services.','["Income Tax Personal and Business","Bookkeeping & Payroll Services","Incorporate Business","Tax Audit Representation","Notary Services","Translation & Language Support"]','tax services, accounting, bookkeeping, payroll services, business incorporation, tax audit representation, notary services, translation and language support','completed','2025-08-24T10:14:24.653Z','firecrawl','{"locally_owned":true,"specialty_focus":"comprehensive tax and accounting services"}',NULL,NULL,NULL);
