INSERT INTO businesses VALUES('10e07524-43b3-4b7a-a9c8-fd6ae10be61e','The Chamber Page Lake Powell','48 South Lake Powell Blvd., Page, AZ 86040',36.90778319999999723,-111.4787670999999989,'928-645-2741','www.pagechamber.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','nonprofit_community','community_center','The Chamber Page Lake Powell is a community-centered business that offers a wide range of services to both residents and visitors of Page, Arizona. It distinguishes itself by hosting various events, providing tourist information, and supporting local businesses. The Chamber has been serving the area since the 1960s, making it a well-established part of the community. It operates the official Visitor Center for the Page and Lake Powell Area, known as The Hub, where visitors can find local information and book tours. The Chamber also assists other organizations with projects throughout Page and supports the local Community College.','["Event hosting","Tourist information","Business networking","Community support"]','Chamber of Commerce, Page Lake Powell, community services, tourist information, local events, business support','completed','2025-08-24T10:38:38.133Z','firecrawl','{"locally_owned":true,"specialty_focus":"Community services and local business support"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('2dd9897e-d975-4224-bd3d-fbfa6ba5c097','The Clarendon Hotel And Spa','401 W Clarendon Ave, Phoenix, AZ 85013',33.49107060000000046,-112.0795437999999962,'(402) 306-4827','goclarendon.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','arts_entertainment','event_venue','The Clarendon Hotel and Spa is an adults-only oasis located in Phoenix, Arizona. It distinguishes itself as a sophisticated and luxurious destination for relaxation and entertainment. The hotel offers a variety of services including accommodation, spa treatments, and event hosting. It serves individuals looking for a serene getaway, couples on romantic escapades, and groups planning events or celebrations. The Clarendon Hotel and Spa is known for its top-notch customer service, unique ambiance, and high-quality offerings.','["Accommodation","Spa Treatments","Event Hosting"]','Hotel, Spa, Adults-only, Event Venue, Luxury, Phoenix','completed','2025-08-25T00:41:27.573Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Adults-only Hotel and Spa"}',NULL,NULL,NULL);
