INSERT INTO businesses VALUES('30c7e793-b8da-4cdb-b9bf-de3d2f2809a5','The Farish House','816 N 3rd St, Phoenix, AZ 85004',33.45717849999999772,-112.0702748000000071,'602-281-6659','Farishhouse.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','restaurant','The Farish House is a family-owned bistro and wine bar located in the heart of Downtown Phoenix, Arizona. It offers a quaint escape from modern life, serving up classic dishes in a charming turn-of-the-century home and patio setting. The restaurant is known for its unique offerings such as cassoulet, Angus ribeye, mac n’ cheese, and a variety of small bites, cheeses, and charcuterie. It also features a saloon with pre-prohibition era wine estates and cocktails. The Farish House distinguishes itself with its cozy atmosphere, high-quality food, and excellent service.','["Dinner Service","Tea Service","Cassoulet","Angus Ribeye","Mac n’ Cheese","Small Bites","Cheeses","Charcuterie","Wine","Cocktails"]','Bistro, Wine Bar, Downtown Phoenix, Family-owned, Classic Dishes, Pre-Prohibition Era Wine, Cocktails','completed','2025-08-25T00:46:49.599Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Classic dishes served in a cozy, vintage setting with a wide selection of wines and cocktails"}',NULL,NULL,NULL);
