INSERT INTO businesses VALUES('1b68a399-abe4-43ef-ae62-14eba1e44a80','The Farm at Scott Foundation','P.O. Box 4927, Cave Creek, AZ 85327',33.4558737744045942,-112.0351548555024124,'4806889800','https://www.Scott-Foundation.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','nonprofit_community','nonprofit_org','The Farm at Scott Foundation is a nonprofit organization dedicated to serving Arizona''s foster youth. The foundation provides hands-on learning in a farm and family environment, aiming to equip foster youth with confidence, practical skills, values, and a clear vision for their future. The foundation''s work is guided by a dedicated board of trustees and advisors, and a committed team of staff members. The Scott Foundation is committed to building a vibrant, inclusive, and sustainable community while preserving and protecting Arizona''s Sonoran Desert and wildlife.','["Hands-on learning programs","Community building","Sustainable agriculture efforts","Higher education services"]','nonprofit organization, foster youth, hands-on learning, farm environment, family environment, sustainable community, Sonoran Desert, wildlife preservation','completed','2025-08-24T10:59:13.252Z','firecrawl','{"locally_owned":true,"specialty_focus":"Serving Arizona''s foster youth and preserving local environment"}',NULL,NULL,NULL);
