INSERT INTO businesses VALUES('0748171a-57ae-44e4-a8e0-4e47b2baad76','The Regalitos Shop','8627 N 51st Drive, Glendale, AZ 85302',33.56319739999999996,-112.1694908999999996,NULL,'https://theregalitosshop.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','gifts_novelty','The Regalitos Shop is a mother-daughter owned pop-up shop based in Phoenix, AZ that specializes in handmade amigurumi plush animals. Each product is individually handmade, guaranteeing a one-of-a-kind gift. They offer a variety of plush animals, including characters like Minnie Mouse, Groot, and unique animals like cows and capybaras. They also feature cultural items like the Virgen De Guadalupe plush. The shop distinguishes itself by offering unique, handmade products and hosting pop-up events.','["Handmade Amigurumi Plush Animals","Virgen De Guadalupe Handmade Amigurumi Plush","Minnie Handmade Amigurumi Plush","Groot Handmade Amigurumi Plush","Cow Handmade Amigurumi Plush","Capibara Handmade Amigurumi Plush"]','handmade, amigurumi, plush animals, gifts, pop-up shop, Phoenix, Arizona','completed','2025-08-24T10:18:11.495Z','firecrawl','{"locally_owned":true,"specialty_focus":"Handmade Amigurumi Plush Animals"}',NULL,NULL,NULL);
