INSERT INTO businesses VALUES('0ee40a28-f067-4106-854b-40ff0af88fc1','The Village Eye Works','10625 N. Tatum Blvd. #110, Phoenix, AZ 85028',33.40884053285837752,-112.0595275131723269,'480-607-0775','www.thevillageeyeworks.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','clothing_fashion','The Village Eye Works is a boutique eyewear business located in Phoenix, Arizona. They specialize in offering unique eyewear from independent designers, serving customers who value individuality and exclusivity in their eyewear choices. The business distinguishes itself by curating a collection of hard-to-find eyewear from independent makers, ensuring customers have access to exclusive designs. Their licensed opticians ensure that the eyewear is made to perfection, providing a blend of style and functionality. The Village Eye Works is a family-owned business and prides itself on providing unparalleled customer service and high-quality eyewear with the latest technology.','["Eyewear from independent designers","Eyewear fitting by licensed opticians"]','eyewear, independent designers, licensed opticians, unique eyewear, Phoenix, Arizona, family-owned','completed','2025-08-24T10:34:02.930Z','firecrawl','{"locally_owned":true,"specialty_focus":"Unique eyewear from independent designers"}',NULL,NULL,NULL);
