INSERT INTO businesses VALUES('024d45c8-9a8e-4f39-a708-9550115fd8a5','Tubac Chamber of Commerce','P.O.Box  1866, Tubac, AZ 85646',33.45681299084709081,-112.0511396742030428,'520-398-2704','www.tubacaz.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','nonprofit_community','community_center','Tubac Chamber of Commerce is a community center type of business located in Tubac, Arizona. It serves the local businesses and community members by promoting economic growth and community development. The Chamber distinguishes itself by providing a platform for businesses to network, collaborate, and grow. It also plays a crucial role in organizing local events, advocating for businesses at the local and state level, and promoting tourism in Tubac.','["Networking Opportunities","Business Advocacy","Local Events Organization","Tourism Promotion"]','Community Center, Business Support, Local Events, Economic Growth, Tourism','completed','2025-08-24T10:07:07.513Z','firecrawl','{"locally_owned":true,"specialty_focus":"Promoting local businesses and community development"}',NULL,NULL,NULL);
