INSERT INTO businesses VALUES('05581fde-2733-4958-962f-c741f4101d34','Tucker Coaching & Consulting','9117 E. Red Bluff Ct, Tucson, AZ 85730',32.21705275102738141,-110.9382541135244793,'5206553080','tuckercoaching.net','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','professional_services','consulting','Tucker Coaching and Consulting is a professional consulting firm based in Tucson, Arizona, specializing in executive, leader, team, and group coaching. They serve senior level global leaders and entrepreneurs, particularly those in transition. Their unique approach involves upgrading the ''inner software'' of leaders, resulting in enhanced organizational culture, increased profitability, and the achievement of stakeholder objectives. They believe in simplicity and the power of community, preferring face-to-face relationships and experiences with their clients. They also offer training and consulting to empower long-term strategy, organizational culture, team psychological safety, and diversity, equity, and inclusion strategy.','["Executive & Leadership Coaching","Team & Group Coaching","Leadership & Culture Consulting & Training"]','executive coaching, leadership development, team coaching, group coaching, organizational culture, profitability, stakeholder objectives, training, consulting, long-term strategy, psychological safety, diversity, equity, inclusion','completed','2025-08-24T10:14:38.082Z','firecrawl','{"locally_owned":true,"specialty_focus":"Executive, Leadership and Team Coaching for Senior Level Global Leaders & Entrepreneurs"}',NULL,NULL,NULL);
