INSERT INTO businesses VALUES('2f2fbca5-e958-4016-b1f9-bbd7c6bcd54e','Tucson Botanical Gardens','2150 N Alvernon Way, Tucson, AZ 85712',32.24839399999999757,-110.9086146000000071,'520-326-9686','tucsonbotanical.org','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','arts_entertainment','recreation','Tucson Botanical Gardens is a recreational business located in the heart of Tucson, Arizona. It serves as an urban oasis, connecting people with plants and nature through art, science, history, and culture. The business is unique for its variety of offerings, including a range of educational classes and events on topics such as gardening, wellness, art, nature, and ecology. It also hosts events like weddings and corporate gatherings, providing a beautiful garden setting and premier catering services. The Tucson Botanical Gardens also features a gift shop and a café, adding to the overall visitor experience.','["Garden Visits","Educational Classes","Event Hosting","Catering Services","Gift Shop","Café"]','Botanical Gardens, Urban Oasis, Educational Classes, Event Hosting, Catering Services, Gift Shop, Café','completed','2025-08-25T00:43:24.444Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Botanical Garden and Educational Resource"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('2295d9b6-ad07-4d10-93e7-42fb0ccfff40','Tucson Chocolate Factory','8998 E Laurie Ann Drive, Tucson, AZ 85747',32.11840790000000112,-110.8006962000000044,'(602) 677-4674','https://www.tucsonchocolatefactory.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','gifts_novelty','Tucson Chocolate Factory is a specialty chocolate business located in Tucson, Arizona. They serve a wide variety of customers, from locals looking for a sweet treat to tourists seeking a unique gift. The business distinguishes itself by offering handmade chocolates, crafted with care and attention to detail. Their range of products includes a variety of chocolate types and flavors, ensuring there is something to suit every palate.','["Handmade chocolates","Gift boxes","Specialty chocolate items"]','chocolate, handmade, gifts, Tucson, Arizona, specialty','completed','2025-08-25T00:17:01.401Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Handmade chocolates"}',NULL,NULL,NULL);
