INSERT INTO businesses VALUES('1991bff1-a8f9-4f9e-94ef-edf88b28b2eb','Tucson CSA','300 East University Boulevard, Ste 146, Tucson, AZ 85705',32.26138860808202935,-111.0186072292403878,NULL,'www.tucsoncsa.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','grocery_market','Tucson CSA is a community-supported agriculture business that connects local producers and consumers of naturally and sustainably grown and produced seasonal foods. They serve people who are interested in participating in a healthier and more sustainable food system. Tucson CSA distinguishes itself by providing a consistent end market for local producers and sharing the risk and rewards of local farming. They offer a variety of products including produce, bread, goat cheese, mushrooms, eggs, meat, and microgreens.','["Produce","Bread","Goat Cheese","Mushrooms","Eggs","Meat","Microgreens"]','Community Supported Agriculture, local produce, sustainable food, seasonal foods, local producers, SNAP','completed','2025-08-24T10:54:19.267Z','firecrawl','{"locally_owned":true,"specialty_focus":"Supporting local producers and promoting sustainable food systems"}',NULL,NULL,NULL);
