INSERT INTO businesses VALUES('04362e49-3ad8-491f-a56a-fc3b456e7a46','Tucson LGBT Chamber of Commerce','PO Box 14312, Tucson, AZ 85732',32.17736712816252265,-110.969967535883157,'520-615-6436','https://tucsonlgbtchamber.org/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','nonprofit_community','nonprofit_org','The Tucson LGBT Chamber of Commerce is a nonprofit organization that serves the LGBTQIA+ and allied business community in Tucson, Arizona. They provide an inclusive space for professionals to network, build their businesses, and receive education on key issues such as diversity, equity, and inclusion. They also advocate for the LGBTQIA+ community, particularly for BIPOC queer voices. Their unique approach to advocacy through an economic lens sets them apart, as they believe that inclusive business is good business.','["Networking opportunities","Educational initiatives","Advocacy for LGBTQIA+ community","Marketing and advertising opportunities"]','LGBTQIA+ advocacy, business networking, diversity education, economic advocacy, inclusive business','completed','2025-08-24T10:11:31.638Z','firecrawl','{"locally_owned":true,"specialty_focus":"LGBTQIA+ business advocacy and networking"}',NULL,NULL,NULL);
