INSERT INTO businesses VALUES('1cd53b44-25c2-4dee-823a-3a574c8faa3f','UniTech Incorporated','2923 W Augusta Ave., Phoenix, AZ 85051',33.55091050000000052,-112.1230783999999972,'602-795-2121','www.4Unitech.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','technology','it_support','UniTech Incorporated is a technology-based business specializing in telecommunications equipment and systems. They serve businesses of all sizes, particularly those in need of support with VOIP or SIP platforms, structured cabling, and Avaya IP Office systems. Their unique selling point is their comprehensive support, from sales to service, for both legacy and modern telecommunication systems. With experienced technicians spread throughout Maricopa County, Pinal, and Pima, Arizona, they assure prompt and efficient service.','["Avaya IP Office Sales and Service","structured cabling","sip provider","telecommunications equipment support"]','Avaya IP Office, telecommunications equipment, structured cabling, sip provider, technical support, VOIP','completed','2025-08-24T11:01:48.345Z','firecrawl','{"locally_owned":true,"specialty_focus":"Telecommunications equipment and systems support"}',NULL,NULL,NULL);
