INSERT INTO businesses VALUES('18ef74b9-ffe7-4316-b0a6-526438d7ee4f','Verde Valley CSA','2773 Middle Verde Rd., Camp Verde, AZ 86322',34.60747260000000125,-111.8605880000000071,'(928) 300-8623','www.verdevalleycsa.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','grocery_market','Verde Valley CSA is a community-supported agriculture business that connects local farmers with food lovers in the Verde Valley area. They provide organic, freshly-picked, local produce to their community, supporting local growers committed to environmental stewardship using no genetically modified seeds or synthetic biocides. Their mission is to provide nutritious produce grown in a sustainable manner, provide access to locally grown produce, and to create a sense of connection and support for the community. They also offer recipes and a local food guide on their website.','["Organic local produce","Weekly basket of produce","Local food guide","Recipes"]','Community Supported Agriculture, local produce, organic farming, sustainable agriculture, Verde Valley, local food guide, recipes','completed','2025-08-24T10:53:39.046Z','firecrawl','{"locally_owned":true,"specialty_focus":"Community Supported Agriculture"}',NULL,NULL,NULL);
