INSERT INTO businesses VALUES('0f2cc9f0-c52a-4bfe-a7be-c41fe1d01b80','Vivapura','960 E. 17th Street, Tucson, AZ 85719',32.21331750000000226,-110.9557224999999931,'877-787-6457','www.vivapura.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','other','unique_business','Vivapura is a unique type of business based in Tucson, Arizona. It does not fit neatly into the standard categories of business taxonomy. The lack of specific information about their offerings and services makes it difficult to categorize them accurately. However, based on their name, which suggests vitality and purity, they might be involved in health and wellness, possibly offering products or services that promote a healthy lifestyle. More information would be needed to provide a more accurate classification.','["Not specified"]','Vivapura, Tucson, Arizona, unique business','completed','2025-08-24T10:34:51.972Z','firecrawl','{"locally_owned":true,"specialty_focus":"Not specified"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('1e4b374a-904d-4c38-9d5e-9be399b7bc9b','Vivapura Superfoods','960 E. 17th St, Tucson, AZ 85719',32.21331750000000226,-110.9557224999999931,'(520) 394-0200','https://www.vivapura.com/','restaurant',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','grocery_market','Vivapura Superfoods is a grocery market type of business with a variety of superfood offerings serving people with health-conscious needs. It distinguishes itself by providing a wide range of organic and raw superfoods, aiming to enhance the health and well-being of its customers. The business is locally owned and operates in Tucson, Arizona.','["Organic Superfoods","Raw Superfoods","Nut Butters","Coconut Products","Cacao Products"]','organic, superfoods, health-conscious, raw food, grocery','completed','2025-08-24T23:58:50.759Z','firecrawl','{"locally_owned":true,"specialty_focus":"Organic and Raw Superfoods"}',NULL,NULL,NULL);
INSERT INTO businesses VALUES('1fe6fcdd-ac78-4d4c-ab1f-2ef6dada12f0','Vortex ATV Rental','989 S Main St Ste A492, Cottonwood, AZ 86326',33.48797685704860073,-112.0788268362597932,'928 235-4520','https://www.vortexatvrental.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','arts_entertainment','recreation','Vortex ATV Rental is a recreational business located in Cottonwood, Arizona, offering a variety of ATV rental services to adventure enthusiasts and tourists. They distinguish themselves by providing self-guided ATV tours, allowing customers to explore Northern Arizona''s secluded terrain at their own pace. They also offer personalized experiences, working closely with their customers to create the perfect adventure tailored to their interests and needs. In addition to ATV rentals, they provide all the necessary gear, maps, GPS tablets, and expert advice to ensure a memorable and safe off-road experience.','["2-Hour ATV Rentals","4-Hour ATV Rentals","8-Hour ATV Rentals","Multiple-Day ATV Rentals","Gear and Equipment Rental","Expert Advice and Trail Tips"]','ATV rentals, self-guided tours, off-road trails, adventure, Northern Arizona, Sedona, personalized experience','completed','2025-08-25T00:09:20.211Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"Self-guided ATV tours and personalized adventure experiences"}',NULL,NULL,NULL);
