INSERT INTO businesses VALUES('0c16fd95-b1c6-4c70-9e78-708a3f4879df','Westgate Garden Design','3010 W Elephant Head Rd, Green Valley, AZ 85622',31.87096186598013503,-110.9848416332258268,'(520) 829-0399','https://westgategardendesign.com/','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','home_services','landscaping_lawn','Westgate Garden Design is a landscape planning and design business based in Arizona. They specialize in permaculture landscape design, creating beautiful and resilient outdoor environments that work in harmony with nature. Their services include expert landscape planning, design, and support during the construction process. They are dedicated to creating landscapes that conserve water, protect wildlife, and provide a source of positive environmental impact. Their unique approach incorporates native plant systems and rainwater harvesting methods, resulting in landscapes that thrive with minimal upkeep.','["Landscape Planning","Permaculture Landscape Design","Construction Process Support"]','landscape planning, permaculture design, outdoor environments, rainwater harvesting, native plant systems, environmental values','completed','2025-08-24T10:29:12.099Z','firecrawl','{"locally_owned":true,"specialty_focus":"Permaculture Landscape Design"}',NULL,NULL,NULL);
