INSERT INTO businesses VALUES('00eb4fed-b691-4963-9e19-8fc8877ff5f5','Whipstone Farm','21640 N. Juniper Ridge Rd., Paulden, AZ 86334',33.43039787822311837,-112.0435219879769307,'928.636.6209','https://whipstone.com/','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','retail_shopping','grocery_market','Whipstone Farm is a family-owned farm located in Paulden, Arizona. They specialize in growing over 100 varieties of vegetables and flowers year-round on their 15-acre property. They are committed to sustainable farming practices, avoiding the use of synthetic fertilizers and chemical pesticides, and instead focusing on creating a healthy farm ecosystem. Their produce and flowers are sold at farmers markets, in CSA boxes, at their honor-system farm stand, and throughout Arizona at natural food stores, restaurants, and florists. They also offer weekly farm shares and seasonal recipes.','["Fresh local produce","CSA boxes","Weekly farm shares","Seasonal recipes","Homegrown flowers"]','family farm, sustainable farming, local produce, CSA boxes, farmers markets, farm shares, seasonal recipes','completed','2025-08-24T10:03:33.002Z','firecrawl','{"locally_owned":true,"specialty_focus":"sustainable farming and local produce"}',NULL,NULL,NULL);
