INSERT INTO businesses VALUES('0c6ef458-678f-4c00-9011-8416e5ed9e67','Whiskey Del Bac','2106 N Forbes Blvd., #103, Tucson, AZ 85745',32.20687708834174857,-111.004504251884157,'(520) 628-9244','www.whiskeydelbac.com','other',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','food_dining','brewery_winery','Whiskey Del Bac is a distillery specializing in American Single Malt whiskey, deeply rooted in the traditions of the Sonoran Desert. Serving whiskey enthusiasts of legal drinking age, the business distinguishes itself by using traditional Scottish distilling methods combined with the unique character of the American Southwest. They offer a variety of own-make whiskeys, with the option to purchase online or visit the distillery for tastings and tours. Their specialty is the Dorado Mesquite Smoked American Single Malt Whiskey, which has been awarded a 90 Point rating by Whisky Advocate.','["Dorado Mesquite Smoked American Single Malt Whiskey","Whiskey Del Bac Classic Single Malt","Sentinel Straight Rye Whiskey","Distillery tours","Whiskey tastings"]','Whiskey Del Bac, distillery, American Single Malt, Sonoran Desert, Scottish distilling methods, whiskey tastings, distillery tours, Dorado Mesquite Smoked','completed','2025-08-24T10:30:30.963Z','firecrawl','{"locally_owned":true,"specialty_focus":"American Single Malt Whiskey"}',NULL,NULL,NULL);
