INSERT INTO businesses VALUES('32386126-9982-4746-bc11-03a90f5666b3','Willmeng Construction','2048 N. 44th St., #200, Phoenix, AZ 85008',33.41755436597166806,-112.0690653770317339,'(480) 968-4755','willmeng.com','professional_services',1,'2024-01-01',1,'active','2025-08-11 18:48:33','2025-08-11 18:48:33','home_services','construction_contractor','Willmeng Construction is a commercial general contractor based in Arizona, specializing in ground-up and tenant improvement projects for the public and private market sectors in the Southwest. They have a diverse portfolio spanning various market sectors, including industrial, civil infrastructure, municipal, public safety, parks & recreation, education, aviation, multifamily, healthcare, hospitality, manufacturing, office, mission critical, and retail. They attribute their success to a wholehearted approach to client service, a relationship-focused culture, and an intentional approach to serving clients through projects large and small. They are recognized as one of the largest locally-owned and operated general contractors in the Southwest, with more than 30 industry awards in the last three years alone.','["ground-up construction","tenant improvement","preconstruction planning","project execution"]','construction, general contractor, tenant improvement, ground-up construction, public sector, private sector, Southwest, industry awards','completed','2025-08-25T00:51:08.419Z','improved_firecrawl','{"locally_owned":true,"specialty_focus":"ground-up and tenant improvement projects"}',NULL,NULL,NULL);
